						{AccountNumber: "ACC_GET_DETAILS", AccountStatus: frcpo.AccountStatusActive, System: frcpo.SystemEBS},
						{AccountNumber: "ACC_GET_DETAILS_MSSL", AccountStatus: frcpo.AccountStatusActive, System: frcpo.SystemMSSL},
						{AccountNumber: "INACTIVE", AccountStatus: frcpo.AccountStatusInactive, System: frcpo.SystemEBS},
					},
				},
			},
		}
	}
	if ua == "" {
		ua = "Friday/3.0.5 (iOS)"
	}
	if premiseID == "" {
		premiseID = "PREMISE_ID"
	}

	r := httptest.NewRequest(http.MethodGet, "/v3/smrd-uportal", nil)
	// Inject bp details
	r = bp.ProvidesDetails(*bpDetails, r)
	// User agent
	r.Header.Set("User-Agent", ua)
	// Premise ID
	rctx := chi.NewRouteContext()
	rctx.URLParams.Add("premise_id", premiseID)
