func TestBPDetailsMiddleware(t *testing.T) {
	testCases := []struct {
		given  bool
		expLen int
	}{
		{given: true, expLen: 0},
		{given: false, expLen: 1},
	}
	for _, tc := range testCases {
		t.Run(fmt.Sprintf("from cache: %v", tc.given), func(t *testing.T) {
			// Given:
			w := httptest.NewRecorder()
			r := httptest.NewRequest(http.MethodPost, "/some/path", nil)
			ctx := r.Context()

			testWriter := testKafkaWriter{}

			oldPostal := postalCodeWriter
			postalCodeWriter = &testWriter
			defer func() { postalCodeWriter = oldPostal }()

			jwt := authc.JWTClaims{
				Sub:          "auth0|1234567890",
				Email:        "test@test.com",
				MobileNumber: "9000000",
			}
			ctx = authc.ProvidesJWT(ctx, jwt)

			bpDetails := bp.Details{
				FromCache: tc.given,
				JWT:       authc.JWTClaims{Sub: "IAM_ID"},
				Premises: []bp.PremisesType{
					{
						ID:     "PREMISEID",
						Type:   "PRIVATE",
						Active: true,
						ContestableDetails: bp.ContestableDetailsType{
							ContestableType: frcpo.ContestableTypeSP,
							AccountNumber:   "MSSLACC1",
							SignedUp:        true,
						},
						Accounts: []bp.AccountsType{
							{
								AccountNumber: "EBSACC1",
								AccountStatus: frcpo.AccountStatusActive,
								System:        frcpo.SystemEBS,
								Utilities:     []string{utilities.TypeGas, utilities.TypeWater},
							},
							{
								AccountNumber: "MSSLACC1",
								AccountStatus: frcpo.AccountStatusActive,
								System:        frcpo.SystemMSSL,
								Utilities:     []string{utilities.TypeElectric},
							},
						},
						SharedResourceDetails: bp.SharedResourceDetailsType{
							Owner:      true,
							OwnerIamID: "IAM_ID",
						},
						AddressDetails: bp.AddressDetailsType{
							Postal: "108982",
						},
					},
				},
			}
			ctx = bp.ProvidesDetailsToContext(bpDetails, ctx)
			g := &errgroup.Group{}
			ctx = setErrgroupContext(ctx, g)

			// Mocks
			ctx = setupMocks(ctx)
			r = r.WithContext(ctx)
			var called bool
			h := web.Handler{H: func(w http.ResponseWriter, r *http.Request) error {
				called = true
				// Then:
				bpDetails := bp.DetailsFromRequest(r)
				require.NotNil(t, bpDetails)
				return nil
			}}

			// When:
			handler := middleware.Adapt(h, BPDetailsMiddleware())
			handler.ServeHTTP(w, r)

			// Then:
			require.True(t, called)
			require.NoError(t, g.Wait())
			require.Len(t, testWriter.Messages, tc.expLen)
		})
	}
}

var (
	_ kafkago.Writer = (*testKafkaWriter)(nil)
)

type testKafkaWriter struct {
	Messages []string
}

func (w *testKafkaWriter) WriteMessage(ctx context.Context, key string, value []byte) error {
	if w.Messages == nil {
		w.Messages = make([]string, 0)
	}
	w.Messages = append(w.Messages, string(value))

	return nil
}

func (w *testKafkaWriter) CloseWriter() error {
	w.Messages = make([]string, 0)

	return nil
}

func setupMocks(ctx context.Context) context.Context {
