	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs/billpreferences"
)

// SwitchEligibility handles request to evaluate whether authenticated user is eligible to switch to e-Bill
func SwitchEligibility(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	// BP details from request
	bpDetails := bp.DetailsFromRequest(r)

	// Validate if authenticated user is receiving paper bills
	onPaperBill, err := isReceivingPaperBills(ctx, bpDetails)
	if err != nil {
		return web.WithStack(err)
	}

	web.RespondJSON(ctx, w, SwitchEligibilityResponse{
		Eligible: onPaperBill,
	}, nil)
	return nil
}

// isReceivingPaperBills returns whether authenticated user has at least one premises receiving paper bills
func isReceivingPaperBills(ctx context.Context, bpDetails *bp.Details) (bool, error) {
	if bpDetails == nil {
		return false, nil
	}

	// Collect bp numbers from bp details
	bpNumbers := []billpreferences.ItemType{}
	for _, it := range bpDetails.BpNumbers {
		if it.System == frcpo.SystemEBS {
			bpNumbers = append(bpNumbers, billpreferences.ItemType{
				BpNo: it.BpNumber,
			})
		}
	}

	prefResp, err := billpreferences.MakeRequest(ctx, billpreferences.Request{
		Item: bpNumbers,
	})
	if err != nil {
		return false, err
	}

	// Evaluate if authenticated user is eligible for ebill promo
	// - If one his/her account is still receiving paper bill, YES
	// - If ALL his/her accounts are no longer receiving paper bill, NO
	for _, it := range prefResp.AccountPref.Item.Array {
		onPaperBill := (it.SuppressPaperOptin.String == billpreferences.FlagFalse)
		if onPaperBill {
			return true, nil
		}
	}
	return false, nil
}

