import (
	"context"
	"encoding/base64"
	"log"
	"os"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	"code.in.spdigital.sg/sp-digital/golang/ravenerrors"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/kafkago"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/timeutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs"
	"github.com/pkg/errors"
	"golang.org/x/sync/errgroup"
)

var postalCodeWriter kafkago.Writer

// PostalCodeDS is struct representation of the object to send over to data team
type PostalCodeDS struct {
	UserIdentity string   `json:"user_identity"`
	Timestamp    int64    `json:"ts"`
	OwnerIamID   string   `json:"owner_iam_id"`
	PremiseID    string   `json:"premise_id"`
	PremiseType  string   `json:"premise_type"`
	PostalCode   string   `json:"postal_code"`
	SharedUsers  []string `json:"shared_users"`
}

// InitPostalCode initialises the datastream pipeline
func InitPostalCode() {
	var err error

	// The mssl_ prefix is a misnomer, as this topic is not restricted to premises postal code for MSSL accounts only.
	// The topic is intended to stream all user's premises postal code both owner and shared, EBS and MSSL accounts
	topicName := "mssl_postalcode"

	// Data stream writer
	postalCodeWriter, err = stubs.NewDataStreamWriter(context.Background(), topicName)
	if err != nil {
		log.Fatalf("%s", errors.Wrap(err, "datastream"))
	}
}

// sendPostalCode sends the postalcode info to data team through kafka
func sendPostalCode(ctx context.Context, g *errgroup.Group, details bp.Details) {
	logger := loglib.GetLogger(ctx)
	if os.Getenv("APPENV") != "test" {
		ctx = loglib.SetLogger(context.Background(), logger)
	}
	if g == nil {
		g, ctx = errgroup.WithContext(ctx)
	}

	for _, p := range details.Premises {
		sharedUsers := []string{}
		for _, su := range p.SharedResourceDetails.Users {
			sharedUsers = append(sharedUsers, su.IamID)
		}
		postalCodeDS := PostalCodeDS{
			UserIdentity: details.JWT.Sub,
			Timestamp:    timeutil.NowSGT().Unix(),
			OwnerIamID:   p.SharedResourceDetails.OwnerIamID,
			PremiseID:    p.ID,
			PremiseType:  p.Type,
			PostalCode:   p.AddressDetails.Postal,
			SharedUsers:  sharedUsers,
		}

		g.Go(func() error {
			data, err := sendToKafka(ctx, postalCodeWriter, postalCodeDS)
			if err != nil {
				ravenerrors.Report(err, map[string]string{
					"service":       "send_postalcode_to_kafka",
					"user_identity": postalCodeDS.UserIdentity,
					"premises_id":   p.ID,
				})
				logger.Errorf("postalcode datastream error: %s", err)
				return err
			}

			logger.Infof("postalcode datastream: %s", base64.StdEncoding.EncodeToString(data))
			return nil
		})
	}
}

