					require.Equal(t, "2016-05-27T00:00:00+08:00", it.LastActualAt)
					require.Equal(t, "6374.2", it.LastActualValue)
					require.Equal(t, "2016-04-01T00:00:00+08:00", it.LastSubmittedAt)
