		{"skip meters with invalid code", createMockUportalResponse(t, time.Time{}, "internal/app/v3/smrd/fixtures/ignored.json")},
	}

	for _, tc := range testCases {
		t.Run(tc.desc, func(t *testing.T) {
			// When:
			w, r := createDetailsUportalHTTPRequest("", nil, "", tc.mockResp)
			err := GetDetailsUportal(w, r)

