)

func TestVerifyCacheResults(t *testing.T) {

	testCases := []struct {
		sub      string
		cached   Details
		expected bool
	}{
		{
			sub: "auth0|SAME",
			cached: Details{
				JWT: authc.JWTClaims{Sub: "auth0|SAME"},
			},
			expected: true,
		},
		{
			sub: "jarvis|SAME",
			cached: Details{
				JWT: authc.JWTClaims{Sub: "jarvis|SAME"},
			},
			expected: true,
		},
		{
			sub: "auth0|SAME",
			cached: Details{
				JWT: authc.JWTClaims{Sub: ""},
			},
			expected: false,
		},
		{
			sub: "auth0|SAME",
			cached: Details{
				JWT: authc.JWTClaims{Sub: "jarvis|SAME"},
			},
			expected: false,
		},
		{
			sub: "auth0|SAME",
			cached: Details{
				JWT: authc.JWTClaims{Sub: "auth0|DIFF"},
			},
			expected: false,
		},
	}

	for _, tc := range testCases {
		tc := tc
		t.Run(tc.sub, func(t *testing.T) {
			t.Parallel()
			// Given:
			ctx := context.Background()

			// When:
			result := verifyCacheResults(ctx, tc.sub, tc.cached)

			// Then:
			require.Equal(t, tc.expected, result)
		})
	}
}

