func TestSendPostalCode(t *testing.T) {
	testCases := []struct {
		given    bp.Details
		expected map[string]PostalCodeDS
	}{
		{
			given: bp.Details{
				JWT: authc.JWTClaims{Sub: "THIS_IS_ME"},
				Premises: []bp.PremisesType{
					{
						ID:   "P-ID",
						Type: "3RM",
						SharedResourceDetails: bp.SharedResourceDetailsType{
							OwnerIamID: "I-AM-OWNER",
							Users: []bp.SharedResourceUserType{
								{IamID: "P-ID"},
								{IamID: "SIBLING"},
							},
						},
						AddressDetails: bp.AddressDetailsType{
							Postal: "112233",
						},
					},
					{
						ID:   "CD-ID",
						Type: "CONDO",
						SharedResourceDetails: bp.SharedResourceDetailsType{
							OwnerIamID: "THIS_IS_ME",
							Users:      []bp.SharedResourceUserType{},
						},
						AddressDetails: bp.AddressDetailsType{
							Postal: "556677",
						},
					},
				},
			},
			expected: map[string]PostalCodeDS{
				"THIS_IS_ME": {
					UserIdentity: "THIS_IS_ME",
					OwnerIamID:   "THIS_IS_ME",
					PremiseID:    "CD-ID",
					PremiseType:  "CONDO",
					PostalCode:   "556677",
					SharedUsers:  []string{},
				},
				"I-AM-OWNER": {
					UserIdentity: "THIS_IS_ME",
					OwnerIamID:   "I-AM-OWNER",
					PremiseID:    "P-ID",
					PremiseType:  "3RM",
					PostalCode:   "112233",
					SharedUsers:  []string{"SIBLING", "P-ID"},
				},
			},
		},
		{
			given: bp.Details{
				JWT:      authc.JWTClaims{Sub: "I-AM-OWNER"},
				Premises: []bp.PremisesType{},
			},
			expected: map[string]PostalCodeDS{},
		},
	}

	for i, tc := range testCases {
		tc := tc
		t.Run(strconv.Itoa(i), func(t *testing.T) {
			t.Parallel()

			err := db.Tx(context.Background(), nil, func(tx db.Transactor) error {
				defer tx.Rollback()

				// Given:
				ctx := context.Background()

				old := postalCodeWriter
				testWriter := testKafkaWriter{}
				postalCodeWriter = &testWriter
				defer func() { postalCodeWriter = old }()

				// When:
				g, ctx := errgroup.WithContext(ctx)
				sendPostalCode(ctx, g, tc.given)
				err := g.Wait()

				// Then:
				require.NoError(t, err)
				require.Len(t, testWriter.Messages, len(tc.expected))

				for _, m := range testWriter.Messages {
					assertPostalCodeDS(t, m, tc.expected)
				}
				// after the iteration, all expected should find a match and no one left in the map
				require.Equal(t, 0, len(tc.expected))

				return nil
			}, 0)
			if err != nil && err != sql.ErrTxDone {
				require.FailNow(t, err.Error())
			}
		})
	}
}

func assertPostalCodeDS(t *testing.T, content string, postalCodeDSMap map[string]PostalCodeDS) {
	var result PostalCodeDS
	require.NoError(t, json.Unmarshal([]byte(content), &result))

	if expected, ok := postalCodeDSMap[result.OwnerIamID]; ok {
		require.Equal(t, expected.UserIdentity, result.UserIdentity)
		require.NotEmpty(t, result.Timestamp)
		require.Equal(t, expected.OwnerIamID, result.OwnerIamID)
		require.Equal(t, expected.PremiseID, result.PremiseID)
		require.Equal(t, expected.PremiseType, result.PremiseType)
		require.Equal(t, expected.PostalCode, result.PostalCode)
		require.ElementsMatch(t, expected.SharedUsers, result.SharedUsers)
		//remove the matched entry
		delete(postalCodeDSMap, result.OwnerIamID)
	} else {
		require.True(t, false, "Unexpected PostalCodeDS received")
	}
}

