// daysInMonth is the number of days in a month
const daysInMonth = 31

// frmLaunchDate is the earliest date that PPMS users can query to
var frmLaunchDate = timeutil.Date(2019, 1, 1, 0, 0)

// Charts returns the consumption of a user
func Charts(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	logger := loglib.GetLogger(ctx)

	// Parse request body
	var req chartsRequest
	if _, err := web.ParseAndLogJSONBody(logger, &req, r.Body); err != nil {
		return web.WithStack(err)
	}

	// Retrieve PPMS account from premiseID
	ppmsAcc, err := accountNumber(ctx, req.PremiseID)
	if err != nil {
		return err
	}

	var periodType, returnDateFormat string
	var interval time.Duration
	switch req.GroupedBy {
	case ami.ResponseGroupedByDay:
		periodType = ppms.PeriodDay
		returnDateFormat = "200601021504"
		interval = 30 * time.Minute
	case ami.ResponseGroupedByMonth:
		periodType = ppms.PeriodMonth
		returnDateFormat = "20060102"
		interval = 24 * time.Hour
	case ami.ResponseGroupedByYear:
		periodType = ppms.PeriodYear
		returnDateFormat = "200601"
		interval = daysInMonth * 24 * time.Hour
	default:
		return ErrInvalidPeriodType
	}

	var start, end time.Time
	if req.End == "" {
		// Special handling for initial call by frontend teams, to use server time
		end = timeutil.NowSGT()
		start = end.AddDate(0, -1, 0)
	} else {
		// Parse and validate start date
		start, err = timeutil.ParseDatetimeOrTime(req.Start)
		if err != nil {
			return web.WithStack(ami.ErrFromInvalid)
		}
		// Parse and validate end date
		end, err = timeutil.ParseDatetimeOrTime(req.End)
		if err != nil {
			return web.WithStack(ami.ErrToInvalid)
		}
	}

	consumpRec := ppms.ConsumptionRecRequest{
		AccNo:       ppmsAcc,
		CsumPrdType: periodType,
		BeginDate:   start.Format("20060102"),
		EndDate:     end.Format("20060102"),
	}

	consumpResp, err := ppms.ConsumptionRec(ctx, consumpRec)
	if err != nil {
		return web.WithStack(err)
	}

	groupedData := ami.ResponseGroupMap{}
	for _, rec := range consumpResp.List {
		t, err := time.ParseInLocation(returnDateFormat, rec.CsumPeriod, timeutil.SGT)
		if err != nil {
			return web.NewError(ppms.ErrServer, err.Error())
		}
		var csum float64
		if rec.CsumAmt != "NULL" {
			csum, err = strconv.ParseFloat(rec.CsumAmt, 64)
			if err != nil {
				return web.NewError(ppms.ErrServer, err.Error())
			}
		}

		var groupKey string
		switch req.GroupedBy {
		case ami.ResponseGroupedByDay:
			groupKey = timeutil.Date(t.Year(), t.Month(), t.Day(), 0, 0).Format(time.RFC3339)
		case ami.ResponseGroupedByMonth:
			groupKey = timeutil.Date(t.Year(), t.Month(), 1, 0, 0).Format(time.RFC3339)
		case ami.ResponseGroupedByYear:
			groupKey = timeutil.Date(t.Year(), 1, 1, 0, 0).Format(time.RFC3339)
		default:
			return ErrInvalidPeriodType
		}

		groupedBy, ok := groupedData[groupKey]
		if !ok {
			groupedBy = map[string]ami.DataType{}
		}

		dataPointKey := t.Format(time.RFC3339)
		groupedBy[dataPointKey] = ami.DataType{
			Date:        dataPointKey,
			Consumption: csum,
		}
		groupedData[groupKey] = groupedBy
	}

	// Fill data series gaps
	groupedData = ami.FillSeriesGaps(start, end, req.GroupedBy, interval, groupedData)

	c := ami.ChartsResponse{
		Unit:      utilities.UnitElectric,
		GroupedBy: req.GroupedBy,
		History:   ami.ToHistoryTypes(frmLaunchDate, time.Now(), req.GroupedBy, interval, groupedData), // Convert AMI meter series data to response
	}

	web.RespondJSON(ctx, w, c, nil)
	return nil
}

