func TestExtractResourcesNotInPremises(t *testing.T) {
	testCases := []struct {
		sharedResources []string
		premises        []string
		ownerIamID      string
		expectedOwned   []string
		expectedShared  []string
	}{
		{
			sharedResources: []string{"4"},
			premises:        []string{"1", "2"},
			ownerIamID:      "0",
			expectedOwned:   []string{},
			expectedShared:  []string{"4"},
		},
		{
			sharedResources: []string{"0", "1", "2", "3", "4"},
			premises:        []string{"1", "2", "3"},
			ownerIamID:      "0",
			expectedOwned:   []string{"0"},
			expectedShared:  []string{"4"},
		},
		{
			sharedResources: []string{"0", "1", "2", "3", "4"},
			premises:        []string{},
			ownerIamID:      "0",
			expectedOwned:   []string{"0"},
			expectedShared:  []string{"1", "2", "3", "4"},
		},
		{
			sharedResources: []string{},
			premises:        []string{"1", "2", "3"},
			ownerIamID:      "0",
			expectedOwned:   []string{},
			expectedShared:  []string{},
		},
		{
			sharedResources: []string{"0"},
			premises:        []string{"0"},
			ownerIamID:      "0",
			expectedOwned:   []string{},
			expectedShared:  []string{},
		},
		{
			sharedResources: []string{},
			premises:        []string{"0"},
			ownerIamID:      "0",
			expectedOwned:   []string{},
			expectedShared:  []string{},
		},
	}

	for _, tc := range testCases {
		tc := tc
		t.Run(fmt.Sprintf("o:%d s:%d", len(tc.expectedOwned), len(tc.expectedShared)), func(t *testing.T) {
			t.Parallel()
			// Given:
			sharedResources := []sharedResourceDetails{}
			for _, it := range tc.sharedResources {
				sharedResources = append(sharedResources, sharedResourceDetails{
					PremisesID: it, ResourceID: it, IamID: it,
				})
			}
			premises := []PremisesType{}
			for _, it := range tc.premises {
				premises = append(premises, PremisesType{
					ID:                    it,
					SharedResourceDetails: SharedResourceDetailsType{ID: it, OwnerIamID: it},
				})
			}

			// When:
			owned, shared := extractResourcesNotInPremises(sharedResources, premises, tc.ownerIamID)

			// Then:
			expectedOwned := []sharedResourceDetails{}
			for _, it := range tc.expectedOwned {
				expectedOwned = append(expectedOwned, sharedResourceDetails{
					PremisesID: it, IamID: it, ResourceID: it,
				})
			}
			expectedShared := []sharedResourceDetails{}
			for _, it := range tc.expectedShared {
				expectedShared = append(expectedShared, sharedResourceDetails{
					PremisesID: it, IamID: it, ResourceID: it,
				})
			}
			require.Equal(t, expectedOwned, owned)
			require.Equal(t, expectedShared, shared)
		})
	}
}

