	require.NoError(t, err)
	result := smrdSVC.DetailsResponse{}
	testhelpers.ParseJSONResponse(t, w.Result(), &result)

	// Message
	require.Equal(t, "Your utilities meters are read once every 2 months. In the months when your meters are not read, you may choose to submit your meter reading here. Meter reading submission is optional.", result.Message)

	// Latest submission period
	//   start = SMRD - 3 days (0600)
	//   end   = SMRD + 1 day  (1700)
	expectedStart := smrdate.AddDate(0, 0, -3)
	expectedStart = time.Date(expectedStart.Year(), expectedStart.Month(), expectedStart.Day(), 6, 0, 0, 0, timeutil.SGT)
	expectedEnd := smrdate.AddDate(0, 0, 1)
	expectedEnd = time.Date(expectedEnd.Year(), expectedEnd.Month(), expectedEnd.Day(), 17, 0, 0, 0, timeutil.SGT)

	require.NotNil(t, result.LatestSubmissionPeriod, "Should have submission period information")
	require.Equal(t, smrdate.Format("Jan 2006"), result.LatestSubmissionPeriod.Title, "Should use smrdate.Format(Jan 2006)")
	require.Equal(t, "Actual", result.LatestSubmissionPeriod.PeriodType)
	require.Equal(t, expectedStart.Format(time.RFC3339), result.LatestSubmissionPeriod.StartDate)
	require.Equal(t, expectedEnd.Format(time.RFC3339), result.LatestSubmissionPeriod.EndDate)

	// Meter read information
	require.Equal(t, 3, len(result.Meters), "Should have 3 meters read information")

	// Submission token
