// createDetailsUportalHTTPRequest is a helper method to create a http test request
func createDetailsUportalHTTPRequest(ua string, bpDetails *bp.Details, premiseID string, mockedResp uportalaccountmanagement.GetMeterDetailsResponse) (*httptest.ResponseRecorder, *http.Request) {
	// Defaults
	if bpDetails == nil {
		bpDetails = &bp.Details{
			Premises: []bp.PremisesType{
				{
					ID: "PREMISE_ID",
					ContestableDetails: bp.ContestableDetailsType{
						ContestableType: frcpo.ContestableTypeSP,
					},
					SharedResourceDetails: bp.SharedResourceDetailsType{Owner: true},
					Accounts: []bp.AccountsType{
						{AccountNumber: "ACC_GET_DETAILS", AccountStatus: frcpo.AccountStatusActive, System: frcpo.SystemEBS},
						{AccountNumber: "ACC_GET_DETAILS_MSSL", AccountStatus: frcpo.AccountStatusActive, System: frcpo.SystemMSSL},
						{AccountNumber: "INACTIVE", AccountStatus: frcpo.AccountStatusInactive, System: frcpo.SystemEBS},
					},
				},
			},
		}
	}
	if ua == "" {
		ua = "Friday/3.0.5 (iOS)"
	}
	if premiseID == "" {
		premiseID = "PREMISE_ID"
	}

	r := httptest.NewRequest(http.MethodGet, "/v3/smrd-uportal", nil)
	// Inject bp details
	r = bp.ProvidesDetails(*bpDetails, r)
	// User agent
	r.Header.Set("User-Agent", ua)
	// Premise ID
	rctx := chi.NewRouteContext()
	rctx.URLParams.Add("premise_id", premiseID)
	r = r.WithContext(context.WithValue(r.Context(), chi.RouteCtxKey, rctx))

	// Mocks:
	if !reflect.DeepEqual(mockedResp, uportalaccountmanagement.GetMeterDetailsResponse{}) {
		ctx := uportalaccountmanagement.MockGetMeterDetails(r.Context(), nil, mockedResp, nil)
		r = r.WithContext(ctx)
	}

	w := httptest.NewRecorder()
	return w, r
}

