			mockStubReq: &emds.ElecMeterReadingsRequest{AccountMeterReqList: []emds.ElecMeterReadingsAccountMeterReqList{
				{AccountNumber: "acc1", MeterNumber: "m1"},
			}},
			mockStubResp: emds.ElecMeterReadingsResponse{},
			mockStubErr:  &web.Error{Status: http.StatusInternalServerError, Code: "unknown_error"},
			wantErr:      &web.Error{Status: http.StatusInternalServerError, Code: "unknown_error"},
		},
		"unauthorized account": {
			input: smrdSVC.GetElecMeterReadingsRequest{[]smrdSVC.AccountMeterPair{
				{AccountNumber: "acc1", MeterNumber: "m1"},
				{AccountNumber: "acc1", MeterNumber: "m2"},
				{AccountNumber: "acc2", MeterNumber: "m3"},
