			givenBPDetails: bp.Details{Premises: []bp.PremisesType{
				{
					SharedResourceDetails: bp.SharedResourceDetailsType{Owner: true},
					Accounts:              []bp.AccountsType{{AccountNumber: "acc1"}},
				},
			}},
			wantErr: bp.ErrAccountUnauthorized,
		},
		"unauthorized premises as not owned": {
			input: smrdSVC.GetElecMeterReadingsRequest{[]smrdSVC.AccountMeterPair{
				{AccountNumber: "acc1", MeterNumber: "m1"},
			}},
			givenBPDetails: bp.Details{Premises: []bp.PremisesType{{
				Accounts: []bp.AccountsType{{AccountNumber: "acc1"}},
			}}},
			wantErr: bp.ErrPremiseUnauthorized,
		},
		"no pairs input": {
			wantErr: smrdSVC.ErrElecMeterReadingsNoPairs,
		},
	}
	for name, tc := range tcs {
		t.Run(name, func(t *testing.T) {
			// Given:
			r := httptest.NewRequest(http.MethodPost, "/v3/smrd", testhelpers.NewJSONReader(tc.input))
			r = bp.ProvidesDetails(tc.givenBPDetails, r)
			r = r.WithContext(emds.MockElecMeterReadings(r.Context(), tc.mockStubReq, tc.mockStubResp, tc.mockStubErr))
			w := httptest.NewRecorder()

			// When:
			err := GetElecMeterReadings(w, r)

			// Then:
			if tc.wantErr != nil {
				testhelpers.AssertWebError(t, tc.wantErr.Status, tc.wantErr.Code, err)
			} else {
				require.NoError(t, err)
			}
			result := smrdSVC.MeterInfoResponse{}
			if tc.wantResp == nil {
				noRespExpected(t, w.Result(), &result)
			} else {
				testhelpers.ParseJSONResponse(t, w.Result(), &result)
				require.Equal(t, *tc.wantResp, result)
			}
		})
	}
}

