	}, resp.BpNumbers)

	if includeShared {
		require.Len(t, resp.Premises, 2)
	} else {
		require.Len(t, resp.Premises, 1)
	}

	// Premises
	premise := resp.Premises[0]
	require.Equal(t, "2100487140", premise.ID)
	require.Equal(t, "12 JBM SINGAPORE 160106", premise.Address)
	require.Equal(t, true, premise.Active)
	require.Equal(t, "Private Apartment", premise.Type)
