	require.Equal(t, "1004006729", ebsAccount.BpNumber)
	require.Equal(t, "008936273922", ebsAccount.AccountNumber)
	require.Equal(t, "Active", ebsAccount.AccountStatus)
	require.Equal(t, "DOM", ebsAccount.AccountType)
	require.Equal(t, "12 JBM SINGAPORE 160106", ebsAccount.Address)
