		require.Equal(t, "1000436916", ebsAccount.BpNumber)
		require.Equal(t, "008427504205", ebsAccount.AccountNumber)
		require.Equal(t, "Active", ebsAccount.AccountStatus)
		require.Equal(t, "DOM", ebsAccount.AccountType)
		require.Equal(t, "475 SEMBAWANG DR", ebsAccount.Address)
		require.Equal(t, "", ebsAccount.Email)
		require.Equal(t, "2000673915", ebsAccount.PremiseNumber)
		require.Equal(t, "475", ebsAccount.MailingAddress.BlockOrApartment)
