func TestSwitch(t *testing.T) {
	testCases := []struct {
		completeActivityErr error
	}{
		{nil},
		{oneupapi.ErrCompleteActivityMaxAttempts},
	}

	for _, tc := range testCases {
		tc := tc
		t.Run(fmt.Sprintf("%s", tc.completeActivityErr), func(t *testing.T) {
			t.Parallel()
			// Given:
			r := httptest.NewRequest(http.MethodPost, "/v4/ebill/switch", nil)
			w := httptest.NewRecorder()
			bpDetails := bp.Details{
				JWT: authc.JWTClaims{Sub: "IAMID"},
				Premises: []bp.PremisesType{
					{
						ID:                    "PREMISESID",
						SharedResourceDetails: bp.SharedResourceDetailsType{Owner: true},
						Accounts: []bp.AccountsType{
							{BpNumber: "BP1", AccountNumber: "ACC1", AccountStatus: frcpo.AccountStatusActive},
							{BpNumber: "BP1", AccountNumber: "ACC2", AccountStatus: frcpo.AccountStatusInactive},
							{BpNumber: "BP1", AccountNumber: "ACC3", AccountStatus: frcpo.AccountStatusActive},
							{BpNumber: "BP2", AccountNumber: "ACC4", AccountStatus: frcpo.AccountStatusActive},
							{BpNumber: "BP2", AccountNumber: "ACC5", AccountStatus: frcpo.AccountStatusInactive},
							{BpNumber: "BP2", AccountNumber: "ACC6", AccountStatus: frcpo.AccountStatusInactive, System: frcpo.SystemMSSL},
						},
					},
					{
						ID:                    "SHAREDPRESMISESID",
						SharedResourceDetails: bp.SharedResourceDetailsType{Owner: false},
						Accounts: []bp.AccountsType{
							{BpNumber: "SHAREDBP1", AccountNumber: "SHAREDACC1", AccountStatus: frcpo.AccountStatusActive},
						},
					},
				},
			}
			r = bp.ProvidesDetails(bpDetails, r)

			// Mocks:
			// mock time
			nowSGT = func() time.Time {
				timeSGT := timeutil.NowSGT()
				return time.Date(timeSGT.Year(), timeSGT.Month(), timeSGT.Day(), 00, 00, 00, 000, timeutil.SGT)
			}
			defer func() {
				time.Sleep(time.Millisecond * 100)
				nowSGT = timeutil.NowSGT
			}()
			ctx := r.Context()
			ctx = updatebillpreferences.MockRequestResponse(ctx, nil, updatebillpreferences.Response{Code: sapjson.FromString(updatebillpreferences.CodeSuccess)}, nil)
			expected1UpReq := oneupapi.CompleteActivityRequest{
				Variables: oneupapi.CompleteActivityVariables{
					AccountID:   "IAMID",
					QuestID:     QuestID,
					CompletedAt: nowSGT().Format(time.RFC3339),
				},
			}
			require.NoError(t, expected1UpReq.Format())
			ctx = oneupapi.MockCompleteActivity(ctx, &expected1UpReq, oneupapi.CompleteActivityResponse{}, tc.completeActivityErr)
			r = r.WithContext(ctx)

			// When:
			err := Switch(w, r)

			// Then:
			require.NoError(t, err)
			var result SwitchResponse
			testhelpers.ParseJSONResponse(t, w.Result(), &result)
			require.Equal(t, []string{"ACC1", "ACC3", "ACC4"}, result.AccountNumbers)
		})
	}
}

