func TestSwitchToEbill(t *testing.T) {
	// Given:
	ctx := context.Background()
	given := bp.Details{
		Premises: []bp.PremisesType{
			{
				ID:                    "PREMISESID",
				SharedResourceDetails: bp.SharedResourceDetailsType{Owner: true},
				Accounts: []bp.AccountsType{
					{BpNumber: "BP1", AccountNumber: "ACC1", AccountStatus: frcpo.AccountStatusActive},
					{BpNumber: "BP1", AccountNumber: "ACC2", AccountStatus: frcpo.AccountStatusInactive},
					{BpNumber: "BP1", AccountNumber: "ACC3", AccountStatus: frcpo.AccountStatusActive},
					{BpNumber: "BP2", AccountNumber: "ACC4", AccountStatus: frcpo.AccountStatusActive},
					{BpNumber: "BP2", AccountNumber: "ACC5", AccountStatus: frcpo.AccountStatusInactive},
