					{BpNumber: "SHAREDBP1", AccountNumber: "SHAREDACC1", AccountStatus: frcpo.AccountStatusActive},
				},
			},
		},
	}

	// Expected:
	expectedReq1 := updatebillpreferences.Request{
		BpNo: "BP1",
		AccountPref: updatebillpreferences.AccountPrefType{
			Item: []updatebillpreferences.ItemType{
				{"ACC1", updatebillpreferences.OptInYes, updatebillpreferences.OptInYes},
				{"ACC3", updatebillpreferences.OptInYes, updatebillpreferences.OptInYes},
			},
		},
	}
	expectedReq2 := updatebillpreferences.Request{
		BpNo: "BP2",
		AccountPref: updatebillpreferences.AccountPrefType{
			Item: []updatebillpreferences.ItemType{
				{"ACC4", updatebillpreferences.OptInYes, updatebillpreferences.OptInYes},
			},
		},
	}
	// Mocks:
	ctx = updatebillpreferences.MockRequestResponse(ctx, &expectedReq1, updatebillpreferences.Response{Code: sapjson.FromString(updatebillpreferences.CodeSuccess)}, nil)
	ctx = updatebillpreferences.MockRequestResponse(ctx, &expectedReq2, updatebillpreferences.Response{Code: sapjson.FromString(updatebillpreferences.CodeSuccessEbillNotUpdated)}, nil)

	// When:
	var g errgroup.Group
	result := switchToEbill(ctx, &g, given.GetOwnedAccounts())

	// Then:
	err := g.Wait()
	assert.NoError(t, err)
	expected := []string{"ACC1", "ACC3", "ACC4"}
	require.EqualValues(t, expected, result)
