func TestShare(t *testing.T) {
	err := db.Tx(context.Background(), nil, func(tx db.Transactor) error {
		httpmock.Activate()
		defer httpmock.DeactivateAndReset()
		auth0.HttpMock()
		defer tx.Rollback()

		// Given:
		req := ShareRequest{
			ID:    "2222233333",
			Email: "hans@email.com",
		}
		resourceID := "rid://jarvis/premises?id=IAMID&id=2222233333"
		iamID := "IAMID"
		address := "ADDRESS"
		r := httptest.NewRequest(http.MethodPost, "/v3/premises/share", testhelpers.NewJSONReader(req))
		w := httptest.NewRecorder()
		bpDetails := bp.Details{
			JWT: authc.JWTClaims{
				Sub: iamID,
			},
			Premises: []bp.PremisesType{
				{ID: req.ID, Address: address, SharedResourceDetails: bp.SharedResourceDetailsType{ID: resourceID, Owner: true}, Active: true},
			},
		}
		r = bp.ProvidesDetails(bpDetails, r)
		ctx := r.Context()

		// Prep fixtures:
		ctx = db.ProvidesTxToTestContext(tx, ctx)

		// Mocks:
		mockReq := profileapi.CreateSharedResourceInviteRequest{
			Variables: profileapi.CreateSharedResourceInviteVariables{
				Input: profileapi.CreateSharedResourceInviteInput{
					Email:        req.Email,
					System:       "jarvis",
					ResourceType: "premises",
					ResourceID:   resourceID,
					SystemID:     sharing.NewSharedPremisesID(iamID, req.ID),
					OwnerIamID:   iamID,
				},
			},
		}
		require.NoError(t, mockReq.Format())
		ctx = profileapi.MockCreateSharedResourceInvite(ctx, &mockReq, profileapi.CreateSharedResourceInviteResponse{}, nil)

		responder, err := httpmock.NewJsonResponder(http.StatusOK, profileapi.CreateSharedResourceInviteResponse{})
		require.NoError(t, err)

		httpmock.RegisterResponder(http.MethodPost, profileapi.CreateSharedResourceInviteURL, responder)

		r = r.WithContext(ctx)

		// When:
		err = Share(w, r)

		// Then:
		require.NoError(t, err)

		return nil
	}, 0)
	if err != nil && err != sql.ErrTxDone {
		require.FailNow(t, err.Error())
	}
}

