func TestCharts(t *testing.T) {
	testCases := []struct {
		groupedBy              string
		expectedGroupCount     int
		expectedCount          int
		expectedWithValueCount int
		expectedValue          float64
	}{
		{
			groupedBy:              "month",
			expectedGroupCount:     1,
			expectedCount:          4,
			expectedWithValueCount: 1,
			expectedValue:          0.0980,
		},
	}

	for _, tc := range testCases {
		// Given:
