package bp

import (
	"context"
	"encoding/json"
	"strings"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	"code.in.spdigital.sg/sp-digital/golang/ravenerrors"
	"code.in.spdigital.sg/sp-digital/golang/redact"
	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/authc"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/auth0"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/redis"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/bifrost"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/ycs"
	"github.com/pkg/errors"
	"golang.org/x/sync/errgroup"
)

const (
	// cacheTTL is the bp details cache TTL
	cacheTTL = time.Duration(time.Minute * 2)
)

// Status is the enum for gift status
type Status string

const (
	PENDING_APPROVAL Status = "PENDING_APPROVAL"
	PENDING_DOCUMENT Status = "PENDING_DOCUMENT"
)

// Returns enum in string
func (e Status) String() string {
	return string(e)
}

type BifrostResponse struct {
	CustomerDetails []customerDetailsRequest
	Status          BifrostStatus
}

type BifrostStatus struct {
	Code    string
	SubCode string
	Message string
}

// customerDetailsRequest is a struct representation of a SAP system's respective ebs.CustomerDetailsRequest
type customerDetailsRequest struct {
	ebs.CustomerDetailsRequest
	System string
}

type YCSResponse struct {
	CustomerDetails []customerDetailsRequest
	YCSStatus       YCSStatus
}
type YCSStatus struct {
	Status  string
	Code    string
	Message string
}

// LoadDetails returns the bp details from context (if any) or retrieves the bp details and saves into the cache
func LoadDetails(ctx context.Context, jwtClaims authc.JWTClaims, includeShared bool) (Details, error) {
	var details Details
	logger := loglib.GetLogger(ctx)

	key := strings.TrimSpace(jwtClaims.Sub)
	if key == "" {
		return Details{}, auth0.ErrAccessToken
	}

	// Get from cache
	var cached bool
	if details, cached = Cached(ctx, key); !cached {
		if !ycs.IsBifrostToYCSEnabled() {
			// Retrieve customer details from SAP, etc
			bifrostResponse, err := newCustomerDetailsRequests(ctx, jwtClaims)
			if err == ErrBifrostNoBpNums {
				// Clean-up me:uportal scope if user is linked in Bifrost but has no BP numbers mapping
				_ = deleteMeUPortalScope(ctx, jwtClaims.Sub)
			}
			// Ignore bifrost.ErrBifrostIAMNotFound, since we're allowing non-owner to login
			if err != nil && err != bifrost.ErrBifrostIAMNotFound {
				return Details{}, web.WithStack(err)
			}
			// Company users with sps link in Pending Approval (IP) status
			if bifrostResponse.Status.Message == "IP" {
				details.Status = PENDING_APPROVAL.String()
				details.JWT = jwtClaims
				return details, nil
			}
			// Company users with sps link in Pending Document (PD) status
			if bifrostResponse.Status.Message == "PD" {
				details.Status = PENDING_DOCUMENT.String()
				details.JWT = jwtClaims
				return details, nil
			}

			logger.Debugf("[bp/cache] Loading bp details for %v", key)
			details, err = retrieveDetails(ctx, bifrostResponse.CustomerDetails)
			// Ignore ErrDetailsNoAccounts, since we're allowing non-owner to login
			if err != nil && err != ErrDetailsNoAccounts {
				return Details{}, web.WithStack(err)
			}
		} else {
			// Retrieve customer details from YCS, etc
			ycsResponse, err := newCustomerDetailsRequestsFromYCS(ctx, jwtClaims)
			if err != nil {
				return Details{}, web.WithStack(err)
			}
			if ycsResponse.YCSStatus.Status == ycs.CodeFail {
				// Note: Ignore ycsResponse.YCSStatus.Code == YD_BPLKUP_1001, since we're allowing non-owner to login
				if ycsResponse.YCSStatus.Code == ycs.BPLookupCodeNoBPMappingFound {
					// Clean-up me:uportal scope if user is linked in YCS but has no BP numbers mapping
					_ = deleteMeUPortalScope(ctx, jwtClaims.Sub)
					return Details{}, web.WithStack(ErrYCSNoBpMapping)
				}
				// Company users with sps link in Pending Approval (IP) status
				if ycsResponse.YCSStatus.Code == ycs.BPLookupCodeUserNotActive {
					details.Status = PENDING_APPROVAL.String()
					details.JWT = jwtClaims
					return details, nil
				}
			}

			logger.Debugf("[bp/cache] Loading bp details for %v", key)
			details, err = retrieveDetails(ctx, ycsResponse.CustomerDetails)
			// Ignore ErrDetailsNoAccounts, since we're allowing non-owner to login
			if err != nil && err != ErrDetailsNoAccounts {
				return Details{}, web.WithStack(err)
			}
		}
		// Populate shared resource details for owned premises
		for i, it := range details.Premises {
			details.Premises[i].SharedResourceDetails = setOwnerSharedResourceDetails(it.SharedResourceDetails, jwtClaims)
		}
	}

	// Initialise details response
	details = initDetails(details, jwtClaims)

	// Retrieve shared resources from profile-api
	if includeShared && isSharedPremisesEnabled() {
		// Add shared premises and update shared premises information
		var err error
		details.Premises, err = appendShared(ctx, details.Premises, jwtClaims.Sub)
		if err != nil {
			return Details{}, err
		}
		// Sort premises
		details.Premises = sortPremises(details.Premises)
	}

	// Save bp details to cache
	if !cached {
		if err := saveCache(key, details, cacheTTL); err != nil {
			// Log/report error and ignore
			// Saving into cache should be best-effort
			logger.Errorf("[bp/cache] Error saving bp details to %s cache: %s", key, err)
			ravenerrors.Report(err, map[string]string{
				"key": key,
			})
		}

	}

	// to denote the details have been cached
	details.FromCache = cached
	return details, nil
}

// Cached returns the bp details from the cache
func Cached(ctx context.Context, key string) (Details, bool) {
	logger := loglib.GetLogger(ctx)
	cached, err := getCache(key)
	if err != nil {
		if err == redis.NilReply {
			logger.Debugf("[bp/cache] BP details for %s not in cache", key)
		} else {
			logger.Errorf("[bp/cache] Error retrieving bp details for %s from cache: %s", key, err)
			ravenerrors.Report(err, map[string]string{
				"key": key,
			})
		}
		return Details{}, false
	}

	logBytes, err := json.Marshal(cached)
	if err == nil {
		rbytes, err := redact.JSONBytes(logBytes)
		if err == nil {
			logBytes = rbytes
		}
	}

	// On Sep 23, 2019, we received a bunch of errors from Redis, where SET without NX or XX is causing nil reply/response (where it shouldn't)
	// On Sep 25, 2019, we received reports from consumer ops that some users are seeing incorrect account data.
	// After investigating, we realised those reports coincide with the times where we were encountering nil reply errors.
	// The issue was mitigated when Digital Infra team set up a new Azure-managed Redis instance for Jarvis.
	// We haven't encountered the issue from then until now (Oct 2, 2019).
	//
	// However, the issue is a bit unsettling to SPS, and they want assurance that this thing will never occur again.
	// Option 1: Set up a Digital Infra managed Redis
	// Option 2: Perform a sanity check on the cache results, which may incur performance and resource overhead.
	//
	// SPD decided to go with option 2 (the more kiasu approach), and monitor the performance hit incurred.
	// To be re-evaluated.
	//
	// Sanity check approach:
	// 1. Retrieve BP mapping from bifrost-api
	// 2. Make sure that one of the BP numbers from (1) is in the cached results
	//
	// If we can't find any of the BP numbers returned by bifrost-api in the cached results, ignore the cached results
	if !verifyCacheResults(ctx, key, cached) {
		ravenerrors.Report(errors.WithStack(ErrCacheMismatch), map[string]string{
			"key": key,
		})
		logger.Errorf("[bp/cache] Unexpected cache results from the provided key %v: %s", key, string(logBytes))
		return Details{}, false
	}

	logger.Debugf("[bp/cache] Retrieved cached BP details for %v: %s", key, string(logBytes))

	return cached, true
}

// newCustomerDetailsRequests creates account details requests from the JWT claims
// Note: Previously creates account details requests based on User-Agent source (i.e. FRIDAY or Infinity), retained function/layer for extensibility
func newCustomerDetailsRequests(ctx context.Context, jwtClaims authc.JWTClaims) (BifrostResponse, error) {
	result := BifrostResponse{}
	result.CustomerDetails = []customerDetailsRequest{}
	// Lookup from Bifrost API for BP numbers
	bfResp, err := bifrost.BPLookup(ctx, bifrost.BPLookupRequest{
		IamUserID: jwtClaims.Sub,
	})
	if err != nil && (bfResp.Status.Message == "IP" || bfResp.Status.Message == "PD") {
		// Set status from bifrost response
		var status BifrostStatus
		status.Code = bfResp.Status.Code
		status.Message = bfResp.Status.Message
		status.SubCode = bfResp.Status.SubCode
		result.Status = status
		return result, nil
	}

	if err != nil {
		return result, err
	}

	// No BP numbers
	if len(bfResp.BpMapping) == 0 {
		return result, ErrBifrostNoBpNums
	}

	// Use BP numbers from Bifrost as request params
	for _, it := range bfResp.BpMapping {
		result.CustomerDetails = append(result.CustomerDetails, customerDetailsRequest{
			CustomerDetailsRequest: ebs.CustomerDetailsRequest{
				BpNo: it.BpNo,
			},
			System: bifrost.SystemMapping[it.System],
		})
	}

	return result, nil
}

// retrieveDetails retrieves the bp details (i.e. premises, account, etc) based on the requests provided
func retrieveDetails(ctx context.Context, requests []customerDetailsRequest) (Details, error) {
	g := &errgroup.Group{}

	ebsChan := make(chan ebs.CustomerDetailsResponse, len(requests))
	msslChan := make(chan ebs.CustomerDetailsResponse, len(requests))
	for _, it := range requests {
		var out chan ebs.CustomerDetailsResponse
		switch it.System {
		case frcpo.SystemEBS:
			out = ebsChan
		case frcpo.SystemMSSL:
			out = msslChan
		}

		asyncRetrieveCustomerDetails(ctx, g, out, it)
	}
	if err := g.Wait(); err != nil {
		return Details{}, err
	}

	// Consolidate/collect account details responses into account details
	ebsAccounts, msslAccounts := collectCustomerDetailsResponses(ebsChan, msslChan)

	// Construct response
	result, err := newDetails(ctx, ebsAccounts, msslAccounts)
	if err != nil {
		return Details{}, err
	}

	// No premises/accounts
	if len(result.Premises) == 0 {
		return Details{}, ErrDetailsNoAccounts
	}

	// Asynchronously trigger notifications enrolment
	go enrolNotifications(ctx, ebsAccounts, msslAccounts)

	return result, nil
}

// asyncRetrieveCustomerDetails asynchronously retrieves customer details and
// sends the response to the channel provided
func asyncRetrieveCustomerDetails(ctx context.Context, g *errgroup.Group, out chan ebs.CustomerDetailsResponse, req customerDetailsRequest) {
	g.Go(func() error {
		resp, err := frcpo.CustomerDetails(ctx, req.System, req.CustomerDetailsRequest)
		if err != nil {
			return err
		}
		out <- resp
		return nil
	})
}

// collectCustomerDetailsResponses collects the responses from the provided channels and returns the accounts
func collectCustomerDetailsResponses(ebsChan chan ebs.CustomerDetailsResponse, msslChan chan ebs.CustomerDetailsResponse) ([]ebs.CustomerDetailsBpItem, []ebs.CustomerDetailsBpItem) {
	// Close channels
	close(ebsChan)
	close(msslChan)

	// Collect EBS customer details
	ebsAccounts := []ebs.CustomerDetailsBpItem{}
	for ebsResp := range ebsChan {
		for _, it := range ebsResp.MTCustomerDetailsReadResponse.BpItem {
			ebsAccounts = append(ebsAccounts, it)
		}
	}

	// Collect MSSL customer details
	msslAccounts := []ebs.CustomerDetailsBpItem{}
	for msslResp := range msslChan {
		for _, it := range msslResp.MTCustomerDetailsReadResponse.BpItem {
			msslAccounts = append(msslAccounts, it)
		}
	}

	return ebsAccounts, msslAccounts
}

// initDetails populates missing information in the details response
func initDetails(details Details, jwtClaims authc.JWTClaims) Details {
	if details.BpNumbers == nil {
		details.BpNumbers = []BpNumbersType{}
	}
	if details.Premises == nil {
		details.Premises = []PremisesType{}
	}

	// Override resp.JWT with jwtClaims (from the request's JWT claims)
	details.JWT.Sub = jwtClaims.Sub
	if email := jwtClaims.Email; email != "" {
		details.JWT.Email = email
	}
	if phoneNumber := jwtClaims.PhoneNumber; phoneNumber != "" {
		details.JWT.PhoneNumber = phoneNumber
	}
	if mobileNumber := jwtClaims.MobileNumber; mobileNumber != "" {
		details.JWT.MobileNumber = mobileNumber
	}
	if name := jwtClaims.Name; name != "" {
		details.JWT.Name = name
	}

	return details
}

// setOwnerSharedResourceDetails sets the shared resource details owner information
func setOwnerSharedResourceDetails(it SharedResourceDetailsType, jwtClaims authc.JWTClaims) SharedResourceDetailsType {
	it.Owner = true
	it.OwnerIamID = jwtClaims.Sub
	it.OwnerName = jwtClaims.Name
	it.MaxUsers = 1
	it.Users = make([]SharedResourceUserType, 0)
	it.Invites = make([]SharedResourceInviteType, 0)
	return it
}

// newCustomerDetailsRequests creates account details requests from the JWT claims based on YCS
func newCustomerDetailsRequestsFromYCS(ctx context.Context, jwtClaims authc.JWTClaims) (YCSResponse, error) {
	result := YCSResponse{}
	result.CustomerDetails = []customerDetailsRequest{}

	// Lookup from ycs API for BP numbers
	ycsResp, err := ycs.BPLookup(ctx, ycs.BPLookupRequest{
		IamId: jwtClaims.Sub,
	})
	if err != nil {
		return result, err
	}

	// Set status from failed ycs response
	if ycsResp.Status == ycs.CodeFail {
		var status YCSStatus
		status.Status = ycsResp.Status
		status.Code = ycsResp.Code
		status.Message = ycsResp.Message
		result.YCSStatus = status
		return result, nil
	}
	// Use BP numbers from ycs as request params
	for _, it := range ycsResp.BpMapping {
		result.CustomerDetails = append(result.CustomerDetails, customerDetailsRequest{
			CustomerDetailsRequest: ebs.CustomerDetailsRequest{
				BpNo: it.BpNo,
			},
			System: bifrost.SystemMapping[it.System],
		})
	}

	return result, nil
}

