					require.FailNow(t, "Should not return water meter read details on MSSL account")
				}
				require.Equal(t, "03", it.UtilType.String)
				require.Equal(t, "6,374.2", it.LowerLimit.String)
				require.Equal(t, "6,569.1", it.UpperLimit.String)
				require.Equal(t, "01", it.DecPlace.String)
				seen[it.DeviceNo.String] = true
			case "BU0214229":
				if accNo == msslAccNo {
					require.FailNow(t, "Should not return gas meter read details on MSSL account")
				}
				require.Equal(t, "02", it.UtilType.String)
				require.Equal(t, "517", it.LowerLimit.String)
				require.Equal(t, "716", it.UpperLimit.String)
				require.Equal(t, "00", it.DecPlace.String)
				seen[it.DeviceNo.String] = true
