func TestGetDetailsUportal_Actual(t *testing.T) {
	// Given:
	isActual := true

	// Mock:
	smrdate, mockResp := withinPeriodUportalResponse(t, isActual, false)

	// When:
	w, r := createDetailsUportalHTTPRequest("", nil, "", mockResp)
