func createMockUportalResponse(t *testing.T, smrdate time.Time, templatePath string) uportalaccountmanagement.GetMeterDetailsResponse {
	b, err := projectpath.Read(templatePath)
	require.NoError(t, err)

	// Replace SMRD with argument
	if !smrdate.IsZero() {
		b = []byte(strings.Replace(string(b), "<SMRD>", smrdate.Format("2006-01-02"), -1))
	}
	resp := uportalaccountmanagement.GetMeterDetailsResponse{}
	err = json.Unmarshal([]byte(b), &resp)
	require.NoError(t, err)

	return resp
