func TestLoadDetails(t *testing.T) {
	testCases := []struct {
		includeShared bool
		claims        authc.JWTClaims
	}{
		{false, authc.JWTClaims{Sub: "auth0|IAMID", Email: "IDTOKENEMAIL", Name: "IDTOKENNAME", PhoneNumber: "IDTOKENPHONENUMBER", MobileNumber: "IDTOKENMOBILENUMBER"}},
		{true, authc.JWTClaims{Sub: "auth0|IAMID", Email: "IDTOKENEMAIL", Name: "IDTOKENNAME", PhoneNumber: "IDTOKENPHONENUMBER", MobileNumber: "IDTOKENMOBILENUMBER"}},
	}

	for _, tc := range testCases {
		t.Run(fmt.Sprintf("%t", tc.includeShared), func(t *testing.T) {
			// Given:
			expectedSharedIamID := "SHAREDIAMID"
			RemoveCache(tc.claims.Sub, expectedSharedIamID)
			defer func() { RemoveCache(tc.claims.Sub, expectedSharedIamID) }()
			ctx := context.Background()

			// Mocks:
			// Mock customer account details (for premises, accounts)
			httpmock.Activate()
			defer httpmock.DeactivateAndReset()
			auth0.HttpMock()

			if ycs.IsBifrostToYCSEnabled() {
				ctx = mockCustomerDetailsWithYCS(ctx, tc.claims.Sub)
				responseCustomer, err := httpmock.NewJsonResponse(http.StatusOK,
					ycs.BPLookupResponse{
						BpMapping: []ycs.BPLookupBpMapping{
							{BpNo: "1004006729", System: "E"},
							{BpNo: "7000039455", System: "M"},
						},
					})
				require.NoError(t, err)
				responseShared, err1 := httpmock.NewJsonResponse(http.StatusOK,
					ycs.BPLookupResponse{
						BpMapping: []ycs.BPLookupBpMapping{
							{BpNo: "1000436916", System: "E"},
						},
					})
				require.NoError(t, err1)
				httpmock.RegisterResponder(http.MethodGet, ycs.BPLookupURL, httpmock.ResponderFromMultipleResponses(
					[]*http.Response{
						responseCustomer,
						responseShared,
					},
				))
			} else {
				ctx = mockCustomerDetails(ctx, tc.claims.Sub)
			}
			// Mock push notification enrolment
			ctx = pushnotificationenrolmentbroker.Mock(ctx, frcpo.SystemEBS, "", "internal/stubs/frcpo/ebs/pushnotificationenrolment/fixtures/success.json", nil)
			ctx = pushnotificationenrolmentbroker.Mock(ctx, frcpo.SystemMSSL, "", "internal/stubs/frcpo/mssl/pushnotificationenrolment/fixtures/success.json", nil)
			// Mock peer comparison (for premises type)
			ctx = peercomparisonbroker.Mock(ctx, frcpo.SystemEBS, "", "internal/stubs/frcpo/ebs/peercomparison/fixtures/success_hua.json", nil)
			// Mock meter installation details
			ctx = meterinstallationdetails.Mock(ctx, "", "internal/stubs/frcpo/ebs/meterinstallationdetails/fixtures/success_ami.json", nil)

			// Mock shared BP details
			if tc.includeShared {
				// Mock profile-api shared resources (for retrieving shared resources)
				ctx = profileapi.MockSharedResourcesf(ctx, "", "internal/stubs/profileapi/testdata/sharedresources/success.json", nil)

				u := profileapi.SharedResourcesURL
				httpmock.RegisterResponder(http.MethodPost, u, testhelpers.NewFileResponder(http.StatusOK, "internal/stubs/profileapi/testdata/sharedresources/success.json"))
				// Mock customer account details (for premises, accounts)
				if ycs.IsBifrostToYCSEnabled() {
					ctx = mockSharedCustomerDetailsWithYCS(ctx, expectedSharedIamID)
				} else {
					ctx = mockSharedCustomerDetails(ctx, expectedSharedIamID)
				}
			}

			// When:
			resp, err := LoadDetails(ctx, tc.claims, tc.includeShared)

			// Then:
			require.NoError(t, err)

			// Assert response JWT
			require.Equal(t, tc.claims.Sub, resp.JWT.Sub)
			require.Equal(t, tc.claims.Name, resp.JWT.Name)
			require.Equal(t, tc.claims.Email, resp.JWT.Email)
			require.Equal(t, tc.claims.PhoneNumber, resp.JWT.PhoneNumber)
			require.Equal(t, tc.claims.MobileNumber, resp.JWT.MobileNumber)

			// Assert response
			assertDetails(t, resp, tc.includeShared, expectedSharedIamID)

			// Assert cache
			cached, err := getCache(tc.claims.Sub)
			require.NoError(t, err)
			resp.FromCache = false
			require.Equal(t, cached, resp)
			if tc.includeShared {
				// Assert that shared details were cached
				scached, err := getCache(expectedSharedIamID)
				require.NoError(t, err)
				// Assert cached JWT details were from customer account details (since it wasn't loaded from the user's request)
				require.Equal(t, "BCXBEXXXEEEXXXX", scached.JWT.Name)
				require.Equal(t, "", scached.JWT.Email)
				require.Equal(t, "60000000", scached.JWT.PhoneNumber)
				require.Equal(t, "", scached.JWT.MobileNumber)
			}
		})
	}
}

func TestLoadDetailsFromCache(t *testing.T) {
	t.Parallel()
	// Given:
	iamID := "IAM_LOADFROMCACHE"
	given := authc.JWTClaims{
		Sub:          iamID,
		Email:        "hans@example.com",
		MobileNumber: "88888888",
		PhoneNumber:  "9000000",
	}
	ctx := context.Background()
	expected := Details{
		JWT: given,
		BpNumbers: []BpNumbersType{
			{BpNumber: "1002934995"},
		},
		Premises: []PremisesType{
			{
				ID: "CACHED",
				SharedResourceDetails: SharedResourceDetailsType{
					Owner:      true,
					OwnerIamID: "IAM_LOADFROMCACHE",
				},
				MeterDetails: MeterDetailsType{
					IntervalUtilities: []string{},
				},
				Accounts: []AccountsType{
					{AccountNumber: "CACHED"},
				},
			},
		},
	}
	err := saveCache(iamID, expected, time.Duration(5*time.Second))
	defer removeCache(iamID)
	require.NoError(t, err)

	// Mocks
	if ycs.IsBifrostToYCSEnabled() {
		ctx = ycs.MockBPLookupf(ctx, "", "internal/stubs/bifrost/testdata/bplookup/success.json", nil)
	} else {
		ctx = bifrost.MockBPLookupf(ctx, "", "internal/stubs/bifrost/testdata/bplookup/success.json", nil)
	}

	// When:
	resp, err := LoadDetails(ctx, given, false)

	// Then:
	require.NoError(t, err)
	resp.FromCache = false
	require.Equal(t, expected, resp)
}

