			},
			{
				Active: false,
				Accounts: []bp.AccountsType{
					{
						System:        "ebs",
						BpNumber:      "bp12-prov",
						AccountStatus: frcpo.AccountStatusProv,
					},
				},
				SharedResourceDetails: bp.SharedResourceDetailsType{
					Owner: false,
				},
			},
		},
	}
	expected1 := UserIAMAssociation{
		IamID: iamID1,
		Accounts: []SAPAccountAssociation{
			{
				Source:        "ebs",
				AccountNumber: "bp1acc1",
				BpNumber:      "bp1",
				Utilities:     []string{"gas", "water"},
				Active:        true,
				Owner:         true,
			},
			{
				Source:        "mssl",
				AccountNumber: "bp1acc2",
				BpNumber:      "bp1",
				Utilities:     []string{"elec"},
				Active:        true,
				Owner:         true,
			},
			{
				Source:        "ebs",
				AccountNumber: "bp11acc22",
				BpNumber:      "bp11",
				Utilities:     []string{"water", "elec", "gas"},
				Active:        false,
				Owner:         false,
			},
			{
				Source:        "ebs",
				BpNumber:      "bp12-prov",
				Active:        false,
			},
