	// "auth0-2"
	detail2 := bp.Details{
		JWT: authc.JWTClaims{
			Sub: iamID2,
		},
		Premises: []bp.PremisesType{
			{
				Active: true,
				Accounts: []bp.AccountsType{
					{
						System:        "ebs",
						AccountNumber: "bp2acc1",
						BpNumber:      "bp2",
						Utilities:     []string{"water", "elec", "gas"},
						AccountStatus: frcpo.AccountStatusActive,
					},
					{
						System:        "ebs",
						AccountNumber: "bp2acc2",
						BpNumber:      "bp22",
						Utilities:     []string{"water", "gas"},
						AccountStatus: frcpo.AccountStatusPending,
					},
				},
				SharedResourceDetails: bp.SharedResourceDetailsType{
					Owner: false,
				},
			},
		},
	}
	expected2 := UserIAMAssociation{
		IamID: "auth0-2",
		Accounts: []SAPAccountAssociation{
			{
				Source:        "ebs",
				AccountNumber: "bp2acc1",
				BpNumber:      "bp2",
				Utilities:     []string{"water", "elec", "gas"},
				Active:        true,
				Owner:         false,
			},
			{
				Source:        "ebs",
				AccountNumber: "bp2acc2",
				BpNumber:      "bp22",
				Utilities:     []string{"water", "gas"},
				Active:        false,
				Owner:         false,
			},
		},
	}
	// "auth0-3"
	detail3 := bp.Details{
		JWT: authc.JWTClaims{
			Sub: iamID3,
		},
		Premises: []bp.PremisesType{
			{
				Active:   false,
				Accounts: []bp.AccountsType{},
			},
		},
	}
	expected3 := UserIAMAssociation{
		IamID:    "auth0-3",
		Accounts: []SAPAccountAssociation{},
	}

	sharedReq := httptest.NewRequest(http.MethodPut, "/v3/feature/sharedpremises", nil)
	sharedWriter := httptest.NewRecorder()
	err := bp.ToggleSharedPremisesFeature(sharedWriter, sharedReq)
	require.NoError(t, err)
	defer func() { bp.ToggleSharedPremisesFeature(sharedWriter, sharedReq) }()

	testCases := []struct {
		given    []string
		expected []UserIAMAssociation
	}{
		{
			given:    []string{iamID1, iamID3},
			expected: []UserIAMAssociation{expected1, expected3},
		},
		{
			given:    []string{iamID2},
			expected: []UserIAMAssociation{expected2},
		},
	}

	for i, tc := range testCases {
		tc := tc
		t.Run(strconv.Itoa(i), func(t *testing.T) {
			// Prep fixtures:
			err := bp.SaveCache(iamID1, detail1)
			require.NoError(t, err)
			defer func() { bp.RemoveCache(iamID1) }()

			err = bp.SaveCache(iamID2, detail2)
			require.NoError(t, err)
			defer func() { bp.RemoveCache(iamID2) }()

			err = bp.SaveCache(iamID3, detail3)
			require.NoError(t, err)
			defer func() { bp.RemoveCache(iamID3) }()

			// Given:
			query := url.Values{"iam_ids": tc.given}
			r := httptest.NewRequest(http.MethodGet, "/v4/accounts/all?"+query.Encode(), nil)
			w := httptest.NewRecorder()

			// When:
			err = RetrieveAccountsByIAM(w, r)

			// Then:
			require.NoError(t, err)
			resp := []UserIAMAssociation{}
			testhelpers.ParseJSONResponse(t, w.Result(), &resp)
			require.ElementsMatch(t, tc.expected, resp)
		})
	}
}

