package datastream

import (
	"context"

	"golang.org/x/sync/errgroup"
)

type contextKey string

const (
	errgroupContextKey = contextKey("errgroup")
)

func errgroupFromContext(ctx context.Context) *errgroup.Group {
	value, ok := ctx.Value(errgroupContextKey).(*errgroup.Group)
	if ok {
		return value
	}
	return nil
}

func setErrgroupContext(ctx context.Context, g *errgroup.Group) context.Context {
	return context.WithValue(ctx, interface{}(errgroupContextKey), g)
}

