func mockCustomerTransferStubs(ctx context.Context, t *testing.T, req WholesaleRequest, bpDetails bp.Details, validateResp ebs.CustomerTransferValidationResponse, transferResp ebs.CustomerTransferResponse, jwtClaims authc.JWTClaims, validateErr, transferErr error) context.Context {
	p, err := bpDetails.IsPremisesOwner(req.PremiseID)
	require.NoError(t, err)

	ebsAcc, ok := p.GetActiveEBSAccount()
	require.True(t, ok)

	bpnum, ok := bpDetails.GetBPDetails(ebsAcc.BpNumber)
	require.True(t, ok)

	mockValReq := ebs.CustomerTransferValidationRequest{
		AccNo:       ebsAcc.AccountNumber,
		ActionDate:  req.TurnOnDate.Format("20060102"),
		InitChan:    "PORTAL",
		MeterOption: req.MeteringOption,
		Nric:        bpnum.Nric,
		PostalCode:  sap.ExtractPostal(ebsAcc.Address),
		ProcessID:   TxnTypeSwitchToContestable,
	}
	if req.MeteringOption == MeterOptionSRLP {
		mockValReq.SelfReadFlag = "X"
	}
	ctx = ebs.MockCustomerTransferValidation(ctx, &mockValReq, validateResp, validateErr)

	mockTrfReq := ebs.CustomerTransferRequest{
		AccNo:       ebsAcc.AccountNumber,
		ActionDate:  req.TurnOnDate.Format("20060102"),
		ContactNo:   jwtClaims.MobileNumber,
		Email:       jwtClaims.Email,
		MeterOption: req.MeteringOption,
		PostalCode:  sap.ExtractPostal(ebsAcc.Address),
		ProcessID:   TxnTypeSwitchToContestable,
	}
	if req.MeteringOption == MeterOptionSRLP {
		mockTrfReq.SelfReadFlag = "X"
	}
	return ebs.MockCustomerTransfer(ctx, &mockTrfReq, transferResp, transferErr)

}

