// assertDataTypeArray asserts the values on a []DataType including sort order
func assertDataTypeArray(t *testing.T, expected []DataType, actual []DataType) {
	require.Equal(t, len(expected), len(actual))
	for i, it := range actual {
		require.Equal(t, expected[i].Period.Unix(), it.Period.Unix())
		require.Equal(t, expected[i].Unit, it.Unit)
		require.Equal(t, expected[i].Status, it.Status)
		require.Equal(t, expected[i].Consumption, it.Consumption)
		require.Equal(t, expected[i].PeerComparison, it.PeerComparison)
	}
}

