package ebill

import (
	"context"
	"net/http"
	"time"

	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/timeutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs/updatebillpreferences"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/oneupapi"
	"golang.org/x/sync/errgroup"
)

const (
	// QuestID is the quest ID for switch e-Bill activity
	QuestID = "A-SWITCH-EBILL"
)

var nowSGT = timeutil.NowSGT

// Switch handles requests to switch all accounts/premises to e-Bill
func Switch(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	// BP details from request
	bpDetails := bp.DetailsFromRequest(r)

	// Switch to e-Bill
	g := errgroup.Group{}
	accNos := switchToEbill(ctx, &g, bpDetails.GetOwnedAccounts())
	if err := g.Wait(); err != nil {
		return web.WithStack(err)
	}
	if len(accNos) <= 0 {
		return web.WithStack(ErrNoActiveAccounts)
	}

	// Send activity completion to 1up
	_, err := oneupapi.CompleteActivity(ctx, oneupapi.CompleteActivityRequest{
		Variables: oneupapi.CompleteActivityVariables{
			AccountID:   bpDetails.JWT.Sub,
			QuestID:     QuestID,
			CompletedAt: nowSGT().Format(time.RFC3339),
		},
	})
	// Ignore error if it's because of maximum attempts
	if err != nil && err != oneupapi.ErrCompleteActivityMaxAttempts {
		return web.WithStack(err)
	}

	web.RespondJSON(ctx, w, SwitchResponse{
		AccountNumbers: accNos,
	}, nil)
	return nil
}

// switchToEbill makes update billing preferences requests from the bp details to opt-out of paper bill and opt-in to e-bill
func switchToEbill(ctx context.Context, g *errgroup.Group, accs []bp.AccountsType) []string {
	result := []string{}
	// Collect all accounts and create pref request for each bp number
	prefReqMap := map[string]updatebillpreferences.Request{}
	for _, it := range accs {
		// Skip inactive accounts
		if it.AccountStatus != frcpo.AccountStatusActive {
			continue
		}

		// Skip MSSL accounts
		if it.System == frcpo.SystemMSSL {
			continue
		}

		prefReq, ok := prefReqMap[it.BpNumber]
		if !ok {
			prefReq = updatebillpreferences.Request{
				BpNo: it.BpNumber,
				AccountPref: updatebillpreferences.AccountPrefType{
					Item: []updatebillpreferences.ItemType{},
				},
			}
		}

		prefReq.AccountPref.Item = append(prefReq.AccountPref.Item, updatebillpreferences.ItemType{
			AccNo:              it.AccountNumber,
			EmailOptin:         updatebillpreferences.OptInYes,
			SuppressPaperOptin: updatebillpreferences.OptInYes,
		})
		prefReqMap[it.BpNumber] = prefReq

		result = append(result, it.AccountNumber)
	}

	// Concurrently update all billing preferences
	for _, it := range prefReqMap {
		it := it
		g.Go(func() error {
			resp, err := updatebillpreferences.MakeRequest(ctx, it)
			if err != nil {
				return err
			}

			if updatebillpreferences.IsErrorResponse(resp) {
				return web.NewError(ErrSwitch, resp.FailMsg.String)
			}
			return nil
		})
	}
	return result
}

