// GetDetails returns the meter read details for the provided account number
// and checks if it's within the submission period
//
// The submit meter reading is a two-step process, where:
// Step 1: Get meter read details and check if it's within the submission period.
//
//	If yes, create/generate a submission token for the client to use on
//	submitting of meter readings
//
// Step 2: Submit user readings together with the submission token to ensure that
//
//	the execution of [Step 2] is valid based on the evaluation on [Step 1]
//
// GetDetails is the 1st step of the submit meter reading process
func GetDetails(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	resp := smrdSVC.DetailsResponse{
		Meters: []smrdSVC.MetersType{},
	}

	// Extract bp details
	bpDetails := bp.DetailsFromRequest(r)

	// Get URL params
	premiseID := chi.URLParam(r, "premise_id")
	p, err := bpDetails.IsPremisesOwner(premiseID)
	if err != nil {
		return web.WithStack(err)
	}

	// Get premise details (active accounts, contestable type)
	activeAccs := p.GetAllActiveAccounts()
	contestableType := p.ContestableDetails.ContestableType

	// Validate active accounts
	if len(activeAccs) <= 0 {
		resp.Message = "You don't have any active accounts in this premise"
		web.RespondJSON(ctx, w, resp, nil)
		return nil
	}

	// Retrieve meter read details for all active accounts
	itsByAcc, err := retrieveMeterReadDetails(ctx, contestableType, activeAccs)
	if err != nil {
		return err
	}

	var withinSubPeriod bool
	meters := []smrdSVC.MetersType{}
	submissionDetails := smrdSVC.SubmissionDetails{}
	for accountNo, its := range itsByAcc {
		submissionDetails[accountNo] = []meterreaddetails.ItemType{}
		for _, it := range its {
			// Skip and ignore invalid meter read details
			// - Not success; OR
			if it.Code.String != meterreaddetails.CodeSuccess {
				continue
			}

			// Get earliest SMRD for submission period calculation and response
			// Parse SMRD
			smrdate, err := smrdSVC.ConvertDateFormat(it.Smrd.String)
			if err != nil {
				// Skip meter read details if SMRD is in invalid format
				smrdSVC.ReportErrors(err, accountNo, it.Smrd.String)
				continue
			}

			// Lookup category based on MRO (Meter reading order - means the read that's about to be done) Flag
			// (i.e. Actual, Estimated)
			category := smrdSVC.CategoryLookup[it.MroFlag.String]
			// Calculate submission period from SMRD and category
			subStart, subEnd, err := smrdSVC.CalculateSubmissionPeriod(smrdate, category)
			if err != nil {
				// Skip meter read details if SMR category is invalid/unknown
				smrdSVC.ReportErrors(err, accountNo, category)
				continue
			}

			// Check if now is within submission period
			withinSubPeriod = smrdSVC.IsWithin(timeutil.NowSGT(), subStart, subEnd)
			// Create latest submission period response for this meter
			subPeriod := smrdSVC.LatestSubmissionPeriodType{
				Title:        smrdate.Format("Jan 2006"),
				PeriodType:   category,
				StartDate:    subStart.Format(time.RFC3339),
				EndDate:      subEnd.Format(time.RFC3339),
				WithinPeriod: withinSubPeriod,
			}

			// Populates the LatestSubmissionPeriod information in the response
			resp, err = populateLatestSubmissionPeriod(resp, subPeriod)
			if err != nil {
				return web.WithStack(err)
			}

			// Filter out meters that are not within submission period
			if !withinSubPeriod {
				// Move on and evalute next meter
				continue
			}

			// Populate meter reading information
			m, err := createMeterResponse(accountNo, it)
			if err != nil {
				// Ignore errors on creation of meter response, just skip adding of meter
				smrdSVC.ReportErrors(err, accountNo, it.DeviceNo.String)
				continue
			}
			meters = append(meters, m)

			// Collect valid meter details into submission reference
			submissionDetails[accountNo] = append(submissionDetails[accountNo], meterreaddetails.ItemType{
				NextMnr:     it.NextMnr,
				UtilType:    it.UtilType,
				DeviceNo:    it.DeviceNo,
				LowerLimit:  it.LowerLimit,
				UpperLimit:  it.UpperLimit,
				PreDecPlace: it.PreDecPlace,
				DecPlace:    it.DecPlace,
			})
		}

		if len(submissionDetails[accountNo]) <= 0 {
			delete(submissionDetails, accountNo)
		}
	}

	if resp.LatestSubmissionPeriod == nil {
		// No valid meter read details
		resp.Message = "No scheduled meter reading dates retrieved for this premises"
	} else if !resp.LatestSubmissionPeriod.WithinPeriod {
		// SMRD not within submission period
		resp.Message = "Your utilities meters are read once every 2 months. In the months when your meters are not read, you may choose to submit your meter reading here. Meter reading submission is optional.\n\nYour meter reading is not due for submission yet."
	} else {
		// Within submission period
		resp.Message = "Your utilities meters are read once every 2 months. In the months when your meters are not read, you may choose to submit your meter reading here. Meter reading submission is optional."
		// Populate meters
		resp.Meters = meters

		// Create submission token
		token, err := smrdSVC.CreateSubmissionToken(r.UserAgent(), submissionDetails)
		if err != nil {
			return web.NewError(smrdSVC.ErrTokenGenerationFailed, err.Error())
		}
		resp.SubmissionToken = string(token)
	}

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

// retrieveMeterReadDetails asynchronously retrieve meter read details for the provided account numbers
//
// Caveat:
// As it turns out, it doesn't matter whether you pass EBS or MSSL account number, you'll get ALL utilities meter read details
// Due to a lot of unknowns, we've decided to sort-of follow how UPortal does it, minus some very hard-coded assumptions
//
// To provide more context, this is how UPortal is doing it:
// - Every request is by ACCOUNT NUMBER (from UI)
// - For a selected account number (i.e. EBS, MSSL), retrieve meter read details
//   - If EBS account number is provided, check if elec meter read details has SRLPFLAG=Y, ignore
//   - If EBS account number is provided, under XOBR, don't apply logic above. Include/return meter read details
//   - If MSSL account number is provided, only take elec meter read details. Ignore other utilities
//
// | Utility  | Account number | XOBR | SRLPFLAG | Ignore |
// |:--------:|:--------------:|:----:|:--------:|:------:|
// | elec     | EBS            | N    | Y        | Y      |
// | elec     | EBS            | Y    | Y        | N      |
// | gas      | EBS            | -    | -        | N      |
// | water    | EBS            | -    | -        | N      |
// | elec     | MSSL           | -    | -        | N      |
// | gas      | MSSL           | -    | -        | Y      |
// | water    | MSSL           | -    | -        | Y      |
// - I know. ¯\_(ツ)_/¯
//
// For Jarvis, implementation/assumptions will be as follows:
// - Every request is by PREMISE
// - Collect all active accounts in a premise (i.e. EBS and MSSL)
// - Perform retrieve meter read details on ALL active accounts
// - Based on contestable type, take elec, gas, water from respective system (EBS, MSSL)
//
// | Retailer Identifier | Utility Type | Account Number |
// |:--------------------|:-------------|:---------------|
// | Non-contestable     | electricity  | EBS            |
// | Non-contestable     | gas          | EBS            |
// | Non-contestable     | water        | EBS            |
// | IOBR                | electricity  | EBS            |
// | IOBR                | gas          | EBS            |
// | IOBR                | water        | EBS            |
// | BOBR-C              | electricity  | EBS            |
// | BOBR-C              | gas          | EBS            |
// | BOBR-C              | water        | EBS            |
// | SP Pool             | electricity  | MSSL           |
// | SP Pool             | gas          | EBS            |
// | SP Pool             | water        | EBS            |
// | Retailer            | electricity  | EBS            |
// | Retailer            | gas          | EBS            |
// | Retailer            | water        | EBS            |
func retrieveMeterReadDetails(ctx context.Context, contestableType string, accounts []bp.AccountsType) (map[string][]meterreaddetails.ItemType, error) {
	result := map[string][]meterreaddetails.ItemType{}
	seenMeters := sync.Map{} // Used to dedup

	g := &errgroup.Group{}
	for _, acc := range accounts {
		acc := acc
		g.Go(func() error {
			// Retrieve SMRD and other meter reading details
			resp, err := meterreaddetails.MakeRequest(ctx, meterreaddetails.Request{
				AccNo: sap.StripAccountNo(acc.AccountNumber),
			})
			if err != nil {
				return err
			}

			its := []meterreaddetails.ItemType{}
			for _, it := range resp.Item.Array {

				switch contestableType {
				case frcpo.ContestableTypeSP:
					// SP MSSL Pool
					// - elec -> from MSSL response
					// - gas -> from EBS response
					// - water -> from EBS response
					if acc.System == frcpo.SystemEBS &&
						it.UtilType.String == meterreaddetails.UtilTypeElectric {
						continue
					}
					if acc.System == frcpo.SystemMSSL &&
						it.UtilType.String != meterreaddetails.UtilTypeElectric {
						continue
					}

				default:
					// IOBR / BOBR-C / NCC / Retailer
					// - elec -> from EBS response
					// - gas -> from EBS response
					// - water -> from EBS response
					if acc.System == frcpo.SystemMSSL {
						continue
					}
				}

				if _, ok := seenMeters.Load(it.DeviceNo.String); !ok {
					seenMeters.Store(it.DeviceNo.String, true)
					its = append(its, it)
				}
			}
			result[acc.AccountNumber] = its
			return nil
		})
	}

	if err := g.Wait(); err != nil {
		return nil, err
	}

	return result, nil
}

// populateLatestSubmissionPeriod sets the "earliest" submission period into the response.
// This is to handle cases where the SMRD for all meters are different. Maybe some of them
// are within the period, and some are not.
// https://www.pivotaltracker.com/n/projects/2151656/stories/160473469
func populateLatestSubmissionPeriod(resp smrdSVC.DetailsResponse, subPeriod smrdSVC.LatestSubmissionPeriodType) (smrdSVC.DetailsResponse, error) {
	if resp.LatestSubmissionPeriod == nil {
		resp.LatestSubmissionPeriod = &subPeriod
	} else {
		subEnd, err := time.Parse(time.RFC3339, subPeriod.EndDate)
		if err != nil {
			return resp, web.NewError(smrdSVC.ErrDateInvalid, fmt.Sprintf("Error parsing submission period end date: %v", err.Error()))
		}
		latestSubEnd, err := time.Parse(time.RFC3339, resp.LatestSubmissionPeriod.EndDate)
		if err != nil {
			return resp, web.NewError(smrdSVC.ErrDateInvalid, fmt.Sprintf("Error parsing submission period end date: %v", err.Error()))
		}

		withinSame := resp.LatestSubmissionPeriod.WithinPeriod == subPeriod.WithinPeriod
		switch {
		case withinSame && subEnd.Before(latestSubEnd):
			fallthrough
		case !withinSame && subPeriod.WithinPeriod:
			resp.LatestSubmissionPeriod = &subPeriod
		}
	}
	return resp, nil
}

// createMeterResponse returns a MetersType response out of the meterreaddetails.ItemType
func createMeterResponse(accountNo string, it meterreaddetails.ItemType) (smrdSVC.MetersType, error) {
	// Format last actual reading date
	lastActualDate, err := smrdSVC.FormatDate(it.LastActualReadDate.String)
	if err != nil {
		return smrdSVC.MetersType{}, err
	}
	// Format last actual reading
	lastActualRead, err := smrdSVC.FormatReading(it.LastActualRead.String, it.DecPlace.String)
	if err != nil {
		return smrdSVC.MetersType{}, err
	}
	// Format last actual submitted date
	lastSubmittedDate, err := smrdSVC.FormatDate(it.LastSelfReadDate.String)
	if err != nil {
		return smrdSVC.MetersType{}, err
	}
	// Format last actual submitted
	lastSubmittedRead, err := smrdSVC.FormatReading(it.LastSelfRead.String, it.DecPlace.String)
	if err != nil {
		return smrdSVC.MetersType{}, err
	}

	preDecPlace, decPlace, err := smrdSVC.GetReadingDecPlaces(it)
	if err != nil {
		return smrdSVC.MetersType{}, web.NewError(smrdSVC.ErrMeterPreDecPlace, err.Error())
	}
	minValue, maxValue := smrdSVC.GetReadingMinMax(it)

	return smrdSVC.MetersType{
		AccountNumber:      accountNo,
		MeterID:            it.DeviceNo.String,
		UtilityType:        smrdSVC.UtilTypeLookup[it.UtilType.String],
		LastActualAt:       lastActualDate,
		LastActualValue:    lastActualRead,
		LastSubmittedAt:    lastSubmittedDate,
		LastSubmittedValue: lastSubmittedRead,
		PreDecPlace:        preDecPlace,
		DecPlace:           decPlace,
		Min:                minValue,
		Max:                maxValue,
	}, nil
}

