		premiseID := "AMICHARTS_PREMISE"
		req := chartsRequest{
			PremiseID: premiseID,
			Start:     timeutil.Date(2019, 5, 1, 0, 0).Format("20060102150405"),
			End:       timeutil.Date(2019, 4, 1, 0, 0).Format("20060102150405"),
			GroupedBy: tc.groupedBy,
		}
		r := httptest.NewRequest(http.MethodPost, "/v3/ppms/charts", testhelpers.NewJSONReader(req))
		r = bp.ProvidesDetails(testutil.CreateBpDetails(premiseID, frcpo.SystemEBS, accountNo), r)
		w := httptest.NewRecorder()

		// Mocks:
		ctx := r.Context()
		respJSON := "internal/stubs/ppms/testdata/consumptionrec/success.json"
		expectedResp := ppms.ConsumptionRecResponse{}
		testhelpers.UnmarshalJSONFile(&expectedResp, respJSON)
		ctx = ppms.MockConsumptionRec(ctx, nil, expectedResp, nil)
		r = r.WithContext(ctx)

