		var result ami.ChartsResponse
		testhelpers.ParseJSONResponse(t, w.Result(), &result)

		require.Equal(t, tc.expectedGroupCount, len(result.History), "Should return grouped by based on start and end in request payload")
		var withValue, count int
		for _, h := range result.History {
			for _, it := range h.Data {
				count++
				if it.Consumption > 0.0 {
					withValue++
					require.Equal(t, tc.expectedValue, it.Consumption, "Should sum all readings' value based on groupedBy condition for %v", it.Date)
				}
