				Accounts: []bp.AccountsType{
					{AccountNumber: ebsAccNo, AccountStatus: frcpo.AccountStatusActive, System: frcpo.SystemEBS},
					{AccountNumber: msslAccNo, AccountStatus: frcpo.AccountStatusActive, System: frcpo.SystemMSSL},
					{AccountNumber: "INACTIVE", AccountStatus: frcpo.AccountStatusInactive, System: frcpo.SystemEBS},
				},
			},
		},
	}
	ua := "Friday/3.5.3 (iOS)"
	w, r := createDetailsUportalHTTPRequest(ua, &bpDetails, premiseID, uportalaccountmanagement.GetMeterDetailsResponse{})

	// Mocks:
	ctx := r.Context()
	smrdate, mockEBSResponse := withinPeriodUportalResponse(t, false, false)
	ctx = uportalaccountmanagement.MockGetMeterDetails(ctx, &uportalaccountmanagement.GetMeterDetailsRequest{AccNo: ebsAccNo}, mockEBSResponse, nil)
	_, mockMSSLResponse := withinPeriodUportalResponse(t, false, true)
	ctx = uportalaccountmanagement.MockGetMeterDetails(ctx, &uportalaccountmanagement.GetMeterDetailsRequest{AccNo: msslAccNo}, mockMSSLResponse, nil)
	r = r.WithContext(ctx)

	// When:
	err := GetDetailsUportal(w, r)

	// Then:
	require.NoError(t, err)
	result := smrdSVC.DetailsResponse{}
	testhelpers.ParseJSONResponse(t, w.Result(), &result)

	// Message
	require.Equal(t, "Your utilities meters are read once every 2 months. In the months when your meters are not read, you may choose to submit your meter reading here. Meter reading submission is optional.", result.Message)

	// Latest submission period
	//   start = SMRD - 3 days (0600)
	//   end   = SMRD          (1700)
	expectedStart := smrdate.AddDate(0, 0, -3)
	expectedStart = timeutil.Date(expectedStart.Year(), expectedStart.Month(), expectedStart.Day(), 6, 0)
	expectedEnd := timeutil.Date(smrdate.Year(), smrdate.Month(), smrdate.Day(), 17, 0)

	require.NotNil(t, result.LatestSubmissionPeriod, "Should have submission period information")
	require.Equal(t, smrdate.Format("Jan 2006"), result.LatestSubmissionPeriod.Title, "Should use smrdate.Format(Jan 2006)")
	require.Equal(t, "Estimated", result.LatestSubmissionPeriod.PeriodType)
	require.Equal(t, expectedStart.Format(time.RFC3339), result.LatestSubmissionPeriod.StartDate)
	require.Equal(t, expectedEnd.Format(time.RFC3339), result.LatestSubmissionPeriod.EndDate)

	// Meter read information
	require.Equal(t, 3, len(result.Meters), "Should have 3 meters read information")
	seen := map[string]bool{}
	for _, it := range result.Meters {
		seen[it.UtilityType] = true

		switch it.UtilityType {
		case "electric":
			require.Equal(t, "TA3877359", it.MeterID)
			require.Equal(t, "2016-04-27T00:00:00+08:00", it.LastActualAt)
			require.Equal(t, "10000", it.LastActualValue)
			require.Equal(t, "", it.LastSubmittedAt)
			require.Equal(t, "", it.LastSubmittedValue)
			require.Equal(t, 5, it.PreDecPlace)
			require.Equal(t, 0, it.DecPlace)
			require.EqualValues(t, 10000, it.Min)
			require.EqualValues(t, 22696, it.Max)
		case "gas":
			require.Equal(t, "BU0214229", it.MeterID)
			require.Equal(t, "2016-04-27T00:00:00+08:00", it.LastActualAt)
			require.Equal(t, "517", it.LastActualValue)
			require.Equal(t, "", it.LastSubmittedAt)
			require.Equal(t, "", it.LastSubmittedValue)
			require.Equal(t, 5, it.PreDecPlace)
			require.Equal(t, 0, it.DecPlace)
			require.EqualValues(t, 517, it.Min)
			require.EqualValues(t, 716, it.Max)
		case "water":
			require.Equal(t, "E0001769", it.MeterID)
			require.Equal(t, "2016-05-27T00:00:00+08:00", it.LastActualAt)
			require.Equal(t, "6374.2", it.LastActualValue)
			require.Equal(t, "2016-04-01T00:00:00+08:00", it.LastSubmittedAt)
			require.Equal(t, "5555.0", it.LastSubmittedValue)
			require.Equal(t, 4, it.PreDecPlace)
			require.Equal(t, 1, it.DecPlace)
			require.EqualValues(t, 6374.2, it.Min)
			require.EqualValues(t, 6569.1, it.Max)
		}
	}
	require.Equal(t, 3, len(seen))

	// Submission token
	require.NotEmpty(t, result.SubmissionToken, "Submission token should not be empty")
	tokenUserAgent, detailsResp, err := smrdSVC.ExtractSubmissionToken(result.SubmissionToken)
	require.NoError(t, err)

	// Submit request
	require.Len(t, detailsResp, 2)
	require.Equal(t, ua, tokenUserAgent)
	count := 0
	seen = map[string]bool{}
	for accNo, items := range detailsResp {
		if accNo != ebsAccNo && accNo != msslAccNo {
			require.FailNow(t, "Unexpected account number")
		}
		count = count + len(items)

		for _, it := range items {
			switch it.DeviceNo.String {
			case "TA3877359":
				if accNo == ebsAccNo {
					require.FailNow(t, "Should not return electric meter read details on EBS account")
				}
				require.Equal(t, "01", it.UtilType.String)
				require.Equal(t, "10,000", it.LowerLimit.String)
				require.Equal(t, "22,696", it.UpperLimit.String)
				require.Equal(t, "00", it.DecPlace.String)
				seen[it.DeviceNo.String] = true
			case "E0001769":
				if accNo == msslAccNo {
					require.FailNow(t, "Should not return water meter read details on MSSL account")
				}
				require.Equal(t, "03", it.UtilType.String)
				require.Equal(t, "6,374.2", it.LowerLimit.String)
				require.Equal(t, "6,569.1", it.UpperLimit.String)
				require.Equal(t, "01", it.DecPlace.String)
				seen[it.DeviceNo.String] = true
			case "BU0214229":
				if accNo == msslAccNo {
					require.FailNow(t, "Should not return gas meter read details on MSSL account")
				}
				require.Equal(t, "02", it.UtilType.String)
				require.Equal(t, "517", it.LowerLimit.String)
				require.Equal(t, "716", it.UpperLimit.String)
				require.Equal(t, "00", it.DecPlace.String)
				seen[it.DeviceNo.String] = true
			}
		}
	}

	require.Equal(t, 3, count)
	require.Equal(t, 3, len(seen))
}

