const (
	retailerNameSP = "SP Services Ltd"
)

type ptChanData struct {
	premisesID   string
	premisesType string
}

// newDetails groups EBS and MSSL account details by premises
//
// Scenarios:
// 1. IOBRC or BOBRC - Billing is done on EBS so MSSL account should be transparent to user
//   - Contestable: true
//   - Address: EBS.PremiseAddress
//   - ContestableAccountNumber: EBS.MsslAccountNumber
//   - RetailerName: MSSL.RetailerName
//   - RetailerIdentifier: EBS.RetailerIdentifier (IOBR | BOBR-C)
//   - Accounts: [{EBS}]
//
// 2. SP MSSL Pool - Billing is done on EBS and MSSL
//   - Contestable: true
//   - Address: EBS.PremiseAddress
//   - ContestableAccountNumber: EBS.MsslAccountNumber
//   - RetailerName: MSSL.RetailerName (should be blank)
//   - RetailerIdentifier: MSSL.RetailerIdentifier (should be blank)
//   - Accounts: [{EBS}, {MSSL}]
//
// 3. Retailer - Billing is done on EBS (for water and gas), electric is not managed by SP
//   - Contestable: true
//   - Address: EBS.PremiseAddress
//   - ContestableAccountNumber: EBS.MsslAccountNumber
//   - RetailerName: MSSL.RetailerName (should be retailer name)
//   - RetailerIdentifier: MSSL.RetailerIdentifier (should be blank)
//   - Accounts: [{EBS}]
//
// 4. Non-Contestable
//   - Contestable: false
//   - Address: EBS.PremiseAddress
//   - ContestableAccountNumber: EBS.MsslAccountNumber (should be blank)
//   - RetailerName: EBS.RetailerName (should be blank)
//   - RetailerIdentifier: EBS.RetailerIdentifier (should be blank)
//   - Accounts: [{EBS}]
func newDetails(ctx context.Context, ebsAccs []ebs.CustomerDetailsBpItem, msslAccs []ebs.CustomerDetailsBpItem) (Details, error) {
	result := Details{}

	// Group EBS and MSSL accounts by premises
	groups, err := groupCustomerDetailsByPremises(ctx, ebsAccs, msslAccs)
	if err != nil {
		return Details{}, web.WithStack(err)
	}

	// Extract premises from grouped customer details
	result.Premises, err = newPremisesTypes(ctx, groups)
	if err != nil {
		return Details{}, web.WithStack(err)
	}

	// Extract BP numbers from grouped customer details
	result.BpNumbers, err = newBpNumbersTypes(groups)
	if err != nil {
		return Details{}, web.WithStack(err)
	}

	// Extract JWT details from grouped customer details
	result.JWT, err = newJWTClaims(groups)
	if err != nil {
		return Details{}, web.WithStack(err)
	}
	return result, nil
}

type customerDetailsGroup struct {
	ebsMsslMapping map[string]ebs.CustomerDetailsBpItem
	ebsAccs        []ebs.CustomerDetailsBpItem
	msslAccs       []ebs.CustomerDetailsBpItem
}

// groupCustomerDetailsByPremises groups the EBS and MSSL accounts into a premises map
func groupCustomerDetailsByPremises(ctx context.Context, ebsAccs []ebs.CustomerDetailsBpItem, msslAccs []ebs.CustomerDetailsBpItem) (map[string]customerDetailsGroup, error) {
	logger := loglib.GetLogger(ctx)
	result := map[string]customerDetailsGroup{}
	includedMSSLAccounts := make(map[string]bool)

	for _, ebsAcc := range ebsAccs {
		// Skip if EBS account is in the exclusion list
		if isExcluded(ebsAcc) {
			continue
		}

		// Initialise premises group
		key := ebsAcc.PremiseNo
		g, ok := result[key]
		if !ok {
			g = customerDetailsGroup{
				ebsMsslMapping: map[string]ebs.CustomerDetailsBpItem{},
				ebsAccs:        []ebs.CustomerDetailsBpItem{},
				msslAccs:       []ebs.CustomerDetailsBpItem{},
			}
		}
		// Add EBS account to premises group
		g.ebsAccs = append(g.ebsAccs, ebsAcc)

		// Find mapped MSSL account
		if msslAccNo := ebsAcc.MsslAccountNo; msslAccNo != "" {
			msslAcc, hasMSSL := findByAccountNumber(msslAccs, msslAccNo)
			switch {
			case !hasMSSL:
				// Could not find MSSL account number
				// Possible reason:
				// - MSSL BP number is not yet tagged to user in UPortal

				// Ignore MSSL account and treat user as non-contestable
				logger.Errorf("Error: Could not find MSSL account number %s for %s", ebsAcc.MsslAccountNo, ebsAcc.AccountNo)

			case isExcluded(msslAcc):
				// Excluded account
				// - Reversed account (Reversal use-case); OR
				// - In pending state

				// Ignore MSSL account and treat user as non-contestable
				logger.Debugf("Excluded MSSL account, ignore MSSL account number %s for %s", ebsAcc.MsslAccountNo, ebsAcc.AccountNo)

			case frcpo.IsAccountActive(ebsAcc) && !frcpo.IsAccountActive(msslAcc):
				// Previously contestable customer
				// - EBS is still active
				// - MSSL still linked to the IAM ID
				// - MSSL account is in not in active state

				// Ignore MSSL account and treat user as non-contestable
				logger.Debugf("Active EBS with non-active MSSL account, ignore MSSL account number %s for %s", ebsAcc.MsslAccountNo, ebsAcc.AccountNo)

			default:
				// Collect contestable details for each EBS:MSSL account
				g.ebsMsslMapping[sap.PadAccountNo(ebsAcc.AccountNo)] = msslAcc

				// Add MSSL account to premises ONLY if contestability is on SP Pool
				if frcpo.IsRetailerSP(msslAcc) {
					g.msslAccs = append(g.msslAccs, msslAcc)
				}

				includedMSSLAccounts[msslAccNo] = true
			}
		}

		result[key] = g
	}

	for _, msslAcc := range msslAccs {

		// Skip if MSSL account added to premise already
		if _, ok := includedMSSLAccounts[msslAcc.AccountNo]; ok {
			logger.Debugf("[Regroup With MSSL Only Accounts] MSSL account %s added to premise already", msslAcc.AccountNo)
			continue
		}

		// Skip if MSSL account is in exclusion list
		if isExcluded(msslAcc) {
			logger.Debugf("[Regroup With MSSL Only Accounts] Excluded MSSL account, ignore MSSL account number %s", msslAcc.AccountNo)
			continue
		}

		// Initialise premises group
		key := msslAcc.PremiseNo
		g, ok := result[key]
		if !ok {
			g = customerDetailsGroup{
				msslAccs: []ebs.CustomerDetailsBpItem{},
			}
		}

		// Add MSSL account to premises ONLY if contestability is on SP Pool
		if frcpo.IsRetailerSP(msslAcc) {
			g.msslAccs = append(g.msslAccs, msslAcc)
			logger.Debugf("[Regroup With MSSL Only Accounts] MSSL account %s added to premise %s", msslAcc.AccountNo, msslAcc.PremiseNo)
		}
		result[key] = g
	}

	return result, nil
}

// newBpNumbersTypes returns a list of BpNumbersType from the provided customer details grouped by premises
func newBpNumbersTypes(groups map[string]customerDetailsGroup) ([]BpNumbersType, error) {
	result := []BpNumbersType{}

	var new = func(system string, it ebs.CustomerDetailsBpItem) BpNumbersType {
		return BpNumbersType{
			BpNumber:   it.BpNo,
			BpType:     it.BpType,
			System:     system,
			Salutation: it.Salutation,
			Name:       it.BpName,
			Nric:       it.Nric,
		}
	}

	seen := map[string]bool{}
	for _, group := range groups {
		for _, it := range group.ebsAccs {
			if _, ok := seen[it.BpNo]; !ok {
				result = append(result, new(frcpo.SystemEBS, it))
				seen[it.BpNo] = true
			}
		}
		for _, it := range group.msslAccs {
			if _, ok := seen[it.BpNo]; !ok {
				result = append(result, new(frcpo.SystemMSSL, it))
				seen[it.BpNo] = true
			}
		}
	}

	// Sort by BP number
	sort.SliceStable(result, func(i int, j int) bool {
		return result[i].BpNumber < result[j].BpNumber
	})

	return result, nil
}

// newJWTClaims returns authc.JWTClaims from the provided customer details grouped by premises
func newJWTClaims(groups map[string]customerDetailsGroup) (authc.JWTClaims, error) {
	result := authc.JWTClaims{}

	// Use details from latest premises (higher premises number)
	keys := []string{}
	for k := range groups {
		keys = append(keys, k)
	}
	sort.SliceStable(keys, func(i, j int) bool {
		return keys[i] > keys[j]
	})

	for _, k := range keys {
		group := groups[k]
		for _, it := range group.ebsAccs {
			if result.Email == "" {
				result.Email = it.EmailAddr
			}
			if result.PhoneNumber == "" {
				result.PhoneNumber = it.Phone
			}
			if result.MobileNumber == "" {
				result.MobileNumber = it.Mobile
			}
			if result.Name == "" {
				result.Name = it.BpName
			}
		}
	}

	if result.Email != "" || result.PhoneNumber != "" || result.MobileNumber != "" || result.Name != "" {
		return result, nil
	}

	for _, k := range keys {
		group := groups[k]
		for _, it := range group.msslAccs {
			if result.Email != "" || result.PhoneNumber != "" || result.MobileNumber != "" || result.Name != "" {
				break
			}
			result.Email = it.EmailAddr
			result.PhoneNumber = it.Phone
			result.MobileNumber = it.Mobile
			result.Name = it.BpName
		}
	}

	return result, nil
}

// newPremisesTypes retunrs list of PremisesType from the provided customer details grouped by premises
func newPremisesTypes(ctx context.Context, groups map[string]customerDetailsGroup) ([]PremisesType, error) {
	result := []PremisesType{}

	g := &errgroup.Group{}
	ptChan := make(chan ptChanData, len(groups))
	mdChan := make(chan mdChanData, len(groups))

	for id, group := range groups {
		p := PremisesType{
			ID: id,
			MeterDetails: MeterDetailsType{
				IntervalUtilities: []string{},
			},
			Accounts: []AccountsType{},
			// Set OEM eligibility to default true
			// Deprecated: Backward compatibility
			OemEligible: true,
		}

		// Convert EBS accounts
		for _, it := range group.ebsAccs {
			// Set premises active status
			p.Active = p.Active || frcpo.IsAccountActive(it)
			// Set PPMS details
			p.PpmsDetails = generatePpmsDetails(it)
			p.Accounts = append(p.Accounts, newAccountsType(frcpo.SystemEBS, it))
		}

		// Convert MSSL accounts
		for _, it := range group.msslAccs {
			// Set premises active status
			p.Active = p.Active || frcpo.IsAccountActive(it)
			p.Accounts = append(p.Accounts, newAccountsType(frcpo.SystemMSSL, it))
		}

		// Sort accounts by status, system, and account number
		p.Accounts = sortAccounts(p.Accounts)

		// Find primary EBS/MSSL account (the first/latest EBS/MSSL account)
		var found bool
		for _, it := range p.Accounts {
			if it.System == frcpo.SystemEBS {
				ebsAcc := it
				found = true

				// Set premises address
				p.Address = ebsAcc.Address
				p.SetAddressDetails()

				// Set premise contestable details
				if msslAcc, ok := group.ebsMsslMapping[ebsAcc.AccountNumber]; ok {
					p.ContestableDetails = newContestableDetailsType(msslAcc)
				}

				// Retrieve premises type
				retrievePremisesType(ctx, g, frcpo.SystemEBS, ebsAcc.AccountNumber, ptChanData{premisesID: p.ID}, ptChan)

				// Retrieve meter installation details (i.e. interval utilities, AMI meter, rate category)
				retrieveMeterDetails(ctx, g, frcpo.SystemEBS, p, mdChanData{premisesID: p.ID}, mdChan)

				break
			}

			if it.System == frcpo.SystemMSSL {
				msslAcc := it
				found = true

				// Set premises address
				p.Address = msslAcc.Address
				p.SetAddressDetails()

				// Set premise contestable details
				msslCustDetailsBPItem, hasMSSL := findByAccountNumber(group.msslAccs, it.AccountNumber)
				if hasMSSL {
					p.ContestableDetails = newContestableDetailsType(msslCustDetailsBPItem)
				}

				// Retrieve premises type
				retrievePremisesType(ctx, g, frcpo.SystemMSSL, msslAcc.AccountNumber, ptChanData{premisesID: p.ID}, ptChan)

				// Retrieve meter installation details (i.e. interval utilities, AMI meter, rate category)
				retrieveMeterDetails(ctx, g, frcpo.SystemMSSL, p, mdChanData{premisesID: p.ID}, mdChan)

				break
			}
		}

		if !found {
			// Skip adding of premises if there's no EBS/MSSL account
			// Assumption: There must be at least 1 EBS/MSSL account in a premises
			continue
		}

		result = append(result, p)
	}

	// Wait premises fan-out stub calls
	if err := g.Wait(); err != nil {
		return nil, err
	}
	close(ptChan)
	close(mdChan)

	// Set premises type
	for data := range ptChan {
		// Find premises to update premises type to
		for i, p := range result {
			if data.premisesID == p.ID {
				result[i].Type = data.premisesType
			}
		}
	}

	// Set meter details
	for data := range mdChan {
		// Find premises to update meter details to
		for i, p := range result {
			if data.premisesID == p.ID {
				result[i].MeterDetails.AmiElec = data.amiElec
				result[i].MeterDetails.IntervalUtilities = data.intervalUtilities
				result[i].ContestableDetails.Srlp = data.srlp
			}
		}
	}

	result = sortPremises(result)

	return result, nil
}

// newAccountsType creates an AccountsType based on customer details response
func newAccountsType(system string, it ebs.CustomerDetailsBpItem) AccountsType {
	result := AccountsType{
		System:        system,
		AccountNumber: sap.PadAccountNo(it.AccountNo),
		AccountStatus: it.AccountStatus,
		AccountType:   it.AccountType,
		BpNumber:      it.BpNo,
		Address:       it.PremiseAddr,
		Email:         it.EmailAddr,
		PremiseNumber: it.PremiseNo,
		MailingAddress: MailingAddressType{
			BlockOrApartment: it.BlkNo,
			Street:           it.Street,
			Unit:             it.UnitNo,
			PostalCode:       it.Postcode,
		},
		MoveInDate:  "",
		MoveOutDate: "",
		Utilities:   []string{},
	}

	// PROV is a new state added in EBS (Oct 2021), for new BP accounts that are created, but does not have any active accounts associated with it yet
	// PROV state will be considered as INACTIVE w.r.t Jarvis and Infinity App
	if system == frcpo.SystemEBS && result.AccountStatus == frcpo.AccountStatusProv {
		result.AccountStatus = frcpo.AccountStatusInactive
	}

	// Move in date
	if it.MoveinDate != frcpo.MoveInOutDateNA &&
		it.MoveinDate != frcpo.MoveInOutDateNil {
		midate, err := time.ParseInLocation(frcpo.MoveInOutDateLayout, it.MoveinDate, timeutil.SGT)
		if err != nil {
			ravenerrors.Report(errors.Wrap(err, "move in date"), map[string]string{
				"account_number": result.AccountNumber,
				"system":         system,
			})
		} else {
			result.MoveInDate = midate.Format(time.RFC3339)
		}
	}

	// Move out date
	if it.MoveoutDate != frcpo.MoveInOutDateNA &&
		it.MoveoutDate != frcpo.MoveInOutDateNil &&
		it.MoveoutDate != frcpo.MoveOutDateMax {
		modate, err := time.ParseInLocation(frcpo.MoveInOutDateLayout, it.MoveoutDate, timeutil.SGT)
		if err != nil {
			ravenerrors.Report(errors.Wrap(err, "move out date"), map[string]string{
				"account_number": result.AccountNumber,
				"system":         system,
			})
		} else {
			result.MoveOutDate = modate.Format(time.RFC3339)
		}
	}

	// Utilities
	seen := map[string]bool{}
	for _, it := range strings.Split(it.ActiveSvcs, "|") {
		switch strings.TrimSpace(it) {
		case frcpo.ActiveServicesElec, frcpo.ActiveServicesIOBRElec:
			u := utilities.TypeElectric
			if _, ok := seen[u]; !ok {
				seen[u] = true
				result.Utilities = append(result.Utilities, u)
			}
		case frcpo.ActiveServicesGas:
			u := utilities.TypeGas
			if _, ok := seen[u]; !ok {
				seen[u] = true
				result.Utilities = append(result.Utilities, u)
			}
		case frcpo.ActiveServicesWater:
			u := utilities.TypeWater
			if _, ok := seen[u]; !ok {
				seen[u] = true
				result.Utilities = append(result.Utilities, u)
			}
		case frcpo.ActiveServicesCooling:
			u := utilities.TypeCooling
			if _, ok := seen[u]; !ok {
				seen[u] = true
				result.Utilities = append(result.Utilities, u)
			}
		}
	}
	// Sort utilities
	sort.Strings(result.Utilities)

	return result
}

// findByAccountNumber finds the account details resp by account number
func findByAccountNumber(list []ebs.CustomerDetailsBpItem, accountNo string) (ebs.CustomerDetailsBpItem, bool) {
	for _, it := range list {
		if accountNo == it.AccountNo {
			return it, true
		}
	}
	return ebs.CustomerDetailsBpItem{}, false
}

// newContestableDetailsType returns a new ContestableDetails from the provided MSSL account details
//
// | Contestable type | EBS ret ident | EBS ret name    | MSSL ret ident | MSSL ret name   |
// |:----------------:|:-------------:|:---------------:|:--------------:|:---------------:|
// | None (NCC)       | nil           | nil             | nil            | nil             |
// | SP (MSSL Pool)   | nil           | nil             | nil            | SP Services Ltd |
// | Retailer         | nil           | nil             | nil            | {retailer name} |
// | IOBR             | IOBR          | {retailer name} | IOBR           | {retailer name} |
// | BOBR-C           | BOBR-C        | {retailer name} | BOBR-C         | {retailer name} |
func newContestableDetailsType(acc ebs.CustomerDetailsBpItem) ContestableDetailsType {

	contestableType := frcpo.ContestableTypeRetailer
	switch {
	// IOBR
	case frcpo.IsIOBR(acc):
		contestableType = frcpo.ContestableTypeIOBR

	// BOBRC
	case frcpo.IsBOBRC(acc):
		contestableType = frcpo.ContestableTypeBOBRC

	// Best effort to identify if MSSL Account is with SP
	// 1. Retailer identifier == ""
	// 2. Retailer name is SP or ""
	case frcpo.IsRetailerSP(acc):
		contestableType = frcpo.ContestableTypeSP
	}

	// If EBS account details is passed in, use MSSL account number as
	// contestable account number
	accNo := acc.AccountNo
	if acc.MsslAccountNo != "" {
		accNo = acc.MsslAccountNo
	}

	result := ContestableDetailsType{
		SignedUp:        true,
		AccountNumber:   sap.PadAccountNo(accNo),
		ContestableType: contestableType,
		PremiseNumber:   acc.PremiseNo,
		BpNumber:        acc.BpNo,
	}

	// Handle MSSL information
	switch contestableType {
	case frcpo.ContestableTypeSP:
		// Set retailer name to default SP
		result.RetailerName = retailerNameSP

	case frcpo.ContestableTypeIOBR:
		// Get retailer name from MSSL
		result.RetailerName = acc.RetailerName
		result.RetailerIdentifier = acc.RetailerIdentifier

	case frcpo.ContestableTypeBOBRC:
		// Get retailer name from MSSL
		result.RetailerName = acc.RetailerName
		result.RetailerIdentifier = acc.RetailerIdentifier

	case frcpo.ContestableTypeRetailer:
		// Get retailer name from MSSL
		result.RetailerName = acc.RetailerName
		result.RetailerIdentifier = acc.RetailerIdentifier
	}
	return result
}

// retrievePremisesType retrieves an account's premises type and sends to the channel provided
func retrievePremisesType(ctx context.Context, g *errgroup.Group, accType string, accNo string, data ptChanData, out chan ptChanData) {
	g.Go(func() error {
		resp, err := peercomparisonbroker.MakeRequest(ctx, accType, peercomparison.Request{
			Saccountno: sap.StripAccountNo(accNo),
			Flag:       "hua",
		})
		if err != nil {
			return web.WithStack(err)
		}

		// Sanitise peer comparison premises type for display
		var result string
		switch resp.Premisetype.String {
		case peercomparisonbroker.PremisesTypeHDB1:
			result = "HDB 1-Room Flat"
		case peercomparisonbroker.PremisesTypeHDB2:
			result = "HDB 2-Room Flat"
		case peercomparisonbroker.PremisesTypeHDB3:
			result = "HDB 3-Room Flat"
		case peercomparisonbroker.PremisesTypeHDB4:
			result = "HDB 4-Room Flat"
		case peercomparisonbroker.PremisesTypeHDB5:
			result = "HDB 5-Room Flat"
		case peercomparisonbroker.PremisesTypeHDB6:
			result = "HDB 6-Room Flat"
		case peercomparisonbroker.PremisesTypeHDBExec:
			result = "HDB Executive Flat"
		case peercomparisonbroker.PremisesTypePrivate:
			result = "Private Apartment"
		case peercomparisonbroker.PremisesTypeSemiDetached:
			result = "Semi-Detached House"
		case peercomparisonbroker.PremisesTypeTerrace:
			result = "Terrace House"
		case peercomparisonbroker.PremisesTypeBungalow:
			result = "Bungalow"
		default:
			result = "Others"
		}

		data.premisesType = result
		out <- data
		return nil
	})
}

// isExcluded returns true if the account should be excluded from the premises response
func isExcluded(it ebs.CustomerDetailsBpItem) bool {
	return frcpo.IsAccountPending(it) || frcpo.IsAccountReversed(it)
}

package bp

import (
	"context"
	"encoding/json"
	"log"
	"os"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/redis"
	"github.com/pkg/errors"
)

var (
	client *redis.Client
)

func init() {
	var err error
	client, err = redis.NewClient(context.Background(), os.Getenv("REDIS_URL"))
	if err != nil {
		log.Fatalf("%s", errors.Wrap(err, "redis"))
	}
}

// saveCache saves the bp details into the cache layer
func saveCache(key string, d Details, expiration time.Duration) error {
	if skipCache(key) {
		loglib.GetLogger(context.Background()).Infof("Skipping cache for user %s", key)
		return nil
	}

	jsonStr, err := json.Marshal(d)
	if err != nil {
		return web.NewError(ErrCacheSave, err.Error())
	}

	err = client.Set(key, string(jsonStr), expiration)
	if err == redis.NilReply {
		return web.NewError(ErrCacheSave, "redis nil reply $-1")
	}
	if err != nil {
		return web.NewError(ErrCacheSave, err.Error())
	}

	return nil
}

// removeCache removes the bp details from the cache layer based on key
func removeCache(key string) error {
	_, err := client.Del(key)
	if err != nil {
		return web.NewError(ErrCacheRemove, err.Error())
	}
	return nil
}

// getCache gets the bp details from the cache layer based on the key
func getCache(key string) (Details, error) {
	val, err := client.Get(key)
	if err == redis.NilReply {
		return Details{}, redis.NilReply
	}
	if err != nil {
		return Details{}, web.NewError(ErrCacheGet, err.Error())
	}

	var d Details
	if err = json.Unmarshal([]byte(val), &d); err != nil {
		return Details{}, web.NewError(ErrCacheGet, err.Error())
	}
	return d, nil
}

// =====================
// FOR USE IN TESTS ONLY
// =====================

// SaveCache saves the bp details into the cache layer
func SaveCache(key string, d Details) error {
	if os.Getenv("APPENV") != "test" {
		log.Fatalf("NOT for use in APPENV=" + os.Getenv("APPENV"))
	}
	return saveCache(key, d, time.Duration(5*time.Second))
}

// RemoveCache removes the bp details from the cache layer based on key
func RemoveCache(keys ...string) error {
	if os.Getenv("APPENV") != "test" {
		log.Fatalf("NOT for use in APPENV=" + os.Getenv("APPENV"))
	}
	for _, key := range keys {
		if err := removeCache(key); err != nil {
			return err
		}
	}
	return nil
}

// GetCache gets the bp details from cache layer based on key
func GetCache(key string) (Details, error) {
	if os.Getenv("APPENV") != "test" {
		log.Fatalf("NOT for use in APPENV=" + os.Getenv("APPENV"))
	}
	return getCache(key)
}

