			httpmock.Activate()
			defer httpmock.DeactivateAndReset()
			auth0.HttpMock()
			// Mocks:
			if ycs.IsBifrostToYCSEnabled() {
				ctx = ycs.MockBPLookup(context.Background(), &ycs.BPLookupRequest{IamId: iamID}, tc.mockYCSResp, tc.bifrostErr)

				responder, err := httpmock.NewJsonResponder(http.StatusOK, tc.mockYCSResp)
