			} else {
				ctx = bifrost.MockBPLookup(context.Background(), &bifrost.BPLookupRequest{IamUserID: iamID}, tc.bifrostResp, tc.bifrostErr)
			}
			ctx = profileapi.MockSharedResourcesf(ctx, "", "internal/stubs/profileapi/testdata/sharedresources/empty.json", nil)
			u := profileapi.SharedResourcesURL
			httpmock.RegisterResponder(http.MethodPost, u, testhelpers.NewFileResponder(http.StatusOK, "internal/stubs/profileapi/testdata/sharedresources/empty.json"))
			// When:
			result, err := LoadDetails(ctx, tc.jwt, true)

			// Then:
			if tc.expectedErr == nil {
				require.NoError(t, err)
				require.Equal(t, tc.expected, result)
			} else {
				require.Equal(t, tc.expectedErr, err)
			}
		})
	}
}

