type testRequestParser struct{}

func (p testRequestParser) Parse(ctx context.Context, r io.Reader, mode ProcessMode, c Callback) (int, int, int, error) {
	published := 5
	skipped := 5
	total := 25
	errs := 10

	for i := 0; i < published; i++ {
		c(ctx, "payload")
	}
	return total, skipped, errs, nil
}

type errorRequestParser struct{}

func (p errorRequestParser) Parse(ctx context.Context, r io.Reader, mode ProcessMode, c Callback) (int, int, int, error) {
	return 0, 0, 100, errors.New("parsing error")
}

func TestHandle(t *testing.T) {
	err := db.Tx(context.Background(), nil, func(tx db.Transactor) error {
		defer tx.Rollback()
		// Given:
		nonce := "20170103"
		route := "/notify/success"
		uri := fmt.Sprintf("%s?nonce=%s", route, nonce)
		r := httptest.NewRequest(http.MethodPost, uri, nil)
		w := httptest.NewRecorder()
		r = db.ProvidesTxToTestRequest(tx, r)

		// When:
		err := Handle(w, r, "somenotification", testRequestParser{}, noopCallback)

		// Then:
		require.NoError(t, err)
		resHeader := w.Result().Header
		require.Equal(t, "25", resHeader.Get("X-Count-Total"))
		require.Equal(t, "10", resHeader.Get("X-Count-Error"))
		require.Empty(t, resHeader.Get("X-Nonce-Seen"))

		// Assert that nonce is saved
		exists, err := models.RequestNonces(
			models.RequestNonceWhere.Nonce.EQ(nonce),
			models.RequestNonceWhere.Route.EQ(route)).
			Exists(context.TODO(), tx)
		require.True(t, exists)
		return nil
	}, 0)
	if err != nil && err != sql.ErrTxDone {
		require.FailNow(t, err.Error())
	}
}

