var defaultSharedPremisesFeatureToggle = (os.Getenv("DISABLE_SHARED_PREMISES") != "1")
var sharedPremisesFeatureToggleCacheKey = "feature-sharedpremises"

func init() {
	if err := setSharedPremisesFeatureToggle(defaultSharedPremisesFeatureToggle); err != nil {
		log.Fatalf("%s", errors.Wrap(err, sharedPremisesFeatureToggleCacheKey))
	}
}

// ToggleSharedPremisesFeature handles requests to toggle shared premises feature
func ToggleSharedPremisesFeature(w http.ResponseWriter, r *http.Request) error {
	enabled := isSharedPremisesEnabled()
	if err := setSharedPremisesFeatureToggle(!enabled); err != nil {
		return web.WithStack(err)
	}
	return nil
}

// setSharedPremisesFeatureToggle sets the shared premises feature toggle
func setSharedPremisesFeatureToggle(enabled bool) error {
	key := sharedPremisesFeatureToggleCacheKey
	value := map[string]interface{}{
		"key":   key,
		"value": enabled,
	}

	jsonStr, err := json.Marshal(value)
	if err != nil {
		return web.NewError(ErrCacheSave, err.Error())
	}

	err = client.Set(key, string(jsonStr), time.Hour*24*365*30)
	if err == redis.NilReply {
		return web.NewError(ErrCacheSave, "redis nil reply $-1")
	}
	if err != nil {
		return web.NewError(ErrCacheSave, err.Error())
	}
	return nil
}

// isSharedPremisesEnabled
func isSharedPremisesEnabled() bool {
	key := sharedPremisesFeatureToggleCacheKey
	val, err := client.Get(key)
	if err == redis.NilReply {
		return defaultSharedPremisesFeatureToggle
	}
	if err != nil {
		return defaultSharedPremisesFeatureToggle
	}

	var v map[string]interface{}
	if err = json.Unmarshal([]byte(val), &v); err != nil {
		return defaultSharedPremisesFeatureToggle
	}

	if k, ok := v["key"].(string); !ok || k != key {
		return defaultSharedPremisesFeatureToggle
	}
	result, ok := v["value"].(bool)
	if !ok {
		return defaultSharedPremisesFeatureToggle
	}

	return result

}

// appendShared retrieves missing shared premises from profile-api in the premises provided
//
// Input: List of premises from cache (incl shared) or SAP
//
// Flow:
// 1. Retrieve shared resources from profile-api. This will return list of resources that is accessible to the user
// 2. Based on the shared resources, remove premises that are no longer shared (i.e. in premises list but not in shared resources)
// 3. Extract shared resources that are not in premises (i.e. shared resources that were not loaded in the cache yet)
// 4a. Retrieve premises information of shared resources
// 4b. Delete shared resources (in profile-api) that are no longer owned by the user (i.e. user has moved out
// 5. Add to the list of premises (i.e. input)
// 6. Map shared resources information (i.e. resource ID, users, invites) into premises
func appendShared(ctx context.Context, premises []PremisesType, iamID string) ([]PremisesType, error) {
	// 1. Retrieve shared resources from profile-api. This will return list of resources that is accessible to the user
	sresp, err := profileapi.SharedResources(ctx, profileapi.SharedResourcesRequest{
		Variables: profileapi.SharedResourcesVariables{
			IamID: iamID,
		},
	})
	if err != nil {
		return []PremisesType{}, web.WithStack(err)
	}
	sharedResources := toSharedResourceDetails(sresp.Data.SharedResources.Edges)

	// 2. Based on the shared resources, remove premises that are no longer shared (i.e. in premises list but not in shared resources)
	premises = excludeRevokedSharedResources(premises, sharedResources)

	// 3. Extract shared resources that are not in premises (i.e. shared resources that were not loaded in the cache yet)
	diffOwned, diffShared := extractResourcesNotInPremises(sharedResources, premises, iamID)

	g := &errgroup.Group{}
	// 4a. Retrieve premises information of shared resources
	pchan := lookupSharedPremisesInformation(ctx, g, diffShared)
	// 4b. Delete shared resources (in profile-api) that are no longer diffOwned by the user (i.e. user has moved out
	deleteSharedResources(ctx, g, diffOwned)
	if err := g.Wait(); err != nil {
		return []PremisesType{}, web.WithStack(err)
	}
	close(pchan)

	// 5. Add to the list of premises (i.e. input)
	for p := range pchan {
		premises = append(premises, p)
	}

	// 6. Map shared resources information (i.e. resource ID, users, invites) into premises
	premises = mapWithSharedResources(sresp.Data.SharedResources.MaxUsers, premises, sharedResources, iamID)

	return premises, nil
}

// excludeRevokedSharedResources removes "shared" premises that are no longer in the list of shared resources
func excludeRevokedSharedResources(premises []PremisesType, sharedResources []sharedResourceDetails) []PremisesType {
	result := []PremisesType{}
	for _, it := range premises {
		if it.SharedResourceDetails.Owner {
			// Only evaluating "shared" premises, add if owned
			result = append(result, it)
			continue
		}

		// Check if shared premises is still "shared"
		// Note: If it's not, this means that access has been revoked since the time the details was cached
		if _, found := findSharedResourceDetails(sharedResources, it); found {
			result = append(result, it)
		}
	}
	return result
}

// extractResourcesNotInPremises evaluates and collects shared resources (premises) not in the provided premises list
func extractResourcesNotInPremises(sharedResources []sharedResourceDetails, premises []PremisesType, ownerIamID string) ([]sharedResourceDetails, []sharedResourceDetails) {
	// find finds the premises with the shared resource details provided
	find := func(items []PremisesType, d sharedResourceDetails) (PremisesType, bool) {
		for _, it := range items {
			if it.ID == d.PremisesID &&
				it.SharedResourceDetails.OwnerIamID == d.IamID {
				return it, true
			}
		}
		return PremisesType{}, false
	}

	owned := []sharedResourceDetails{}
	shared := []sharedResourceDetails{}
	for _, it := range sharedResources {
		// Check if resource ID is already in the list of premises
		if _, found := find(premises, it); !found {
			// If not, add to list
			if ownerIamID == it.IamID {
				owned = append(owned, it)
			} else {
				shared = append(shared, it)
			}
		}
	}
	return owned, shared
}

// deleteSharedResources deletes the shared resources provided from profile-api
func deleteSharedResources(ctx context.Context, g *errgroup.Group, items []sharedResourceDetails) {
	logger := loglib.GetLogger(ctx)
	for _, it := range items {
		it := it
		g.Go(func() error {
			_, err := profileapi.DeleteSharedResource(ctx, profileapi.DeleteSharedResourceRequest{
				Variables: profileapi.DeleteSharedResourceVariables{
					ResourceID: it.ResourceID,
				},
			})
			if err != nil {
				logger.Errorf("Error encountered while cleaning up invalid shared resource: %s", it.ResourceID)
				ravenerrors.Report(err, nil)
			}
			return nil
		})
	}
}

// lookupSharedPremisesInformation retrieves the premises (from SAP or cache) of the shared resources provided
func lookupSharedPremisesInformation(ctx context.Context, g *errgroup.Group, items []sharedResourceDetails) chan PremisesType {
	ch := make(chan PremisesType, len(items))
	for _, it := range items {
		it := it

		g.Go(func() error {
			// Retrieve and load shared resource's owner's BP details (premises) into the cache
			details, err := LoadDetails(ctx, authc.JWTClaims{Sub: it.IamID}, false)
			if err != nil {
				return err
			}

			// Find shared premises by premises ID
			if p, found := details.GetPremises(it.PremisesID); found {
				// Set resource owner flag to false since this is a shared premises
				p.SharedResourceDetails.Owner = false
				// Obfuscate/Truncate address due to privacy concerns on shared premises
				p.NonPIIAddress()

				ch <- p
			}
			return nil
		})
	}
	return ch
}

type sharedResourceDetails struct {
	ResourceID string
	PremisesID string
	IamID      string
	Metadata   profileapi.SharedResourcesNode3
}

// toSharedResourceDetails returns a list of shared resource details for the provided shared resources
func toSharedResourceDetails(items []profileapi.SharedResourcesEdges) []sharedResourceDetails {
	result := []sharedResourceDetails{}
	for _, it := range items {
		id, err := sharing.ParseSharedPremisesID(it.Node.SystemID)
		if err != nil {
			continue
		}

		d := sharedResourceDetails{
			ResourceID: it.Node.ID,
			PremisesID: id.PremisesID,
			IamID:      id.IamID,
			Metadata:   it.Node,
		}
		result = append(result, d)
	}
	return result
}

// mapWithSharedResources maps shared resources information into provided premises
func mapWithSharedResources(maxUsers int64, premises []PremisesType, sharedResources []sharedResourceDetails, iamID string) []PremisesType {
	result := []PremisesType{}
	// Map shared resources details into premises
	for _, it := range premises {
		it.SharedResourceDetails.MaxUsers = int(maxUsers)
		it.SharedResourceDetails.Users = []SharedResourceUserType{}
		it.SharedResourceDetails.Invites = []SharedResourceInviteType{}
		if v, found := findSharedResourceDetails(sharedResources, it); found {
			it.SharedResourceDetails.ID = v.ResourceID
			it.SharedResourceDetails.OwnerIamID = v.Metadata.Owner.Node.IamID
			it.SharedResourceDetails.OwnerName = v.Metadata.Owner.Node.Name
			it.SharedResourceDetails.OwnerDisplayName = v.Metadata.Owner.Node.DisplayName
			it.SharedResourceDetails.OwnerEmail = v.Metadata.Owner.Node.Email
			for _, u := range v.Metadata.Users.Edges {
				it.SharedResourceDetails.Users = append(it.SharedResourceDetails.Users, SharedResourceUserType{
					ID:          u.Node.ID,
					IamID:       u.Node.User.Node.IamID,
					Name:        u.Node.User.Node.Name,
					DisplayName: u.Node.User.Node.DisplayName,
					Email:       u.Node.User.Node.Email,
					FullAccess:  u.Node.Metadata.FullAccess,
				})
			}
			for _, i := range v.Metadata.Invites.Edges {
				it.SharedResourceDetails.Invites = append(it.SharedResourceDetails.Invites, SharedResourceInviteType{
					ID:    i.Node.ID,
					Email: i.Node.Email,
				})
			}
		}
		result = append(result, it)
	}
	return result
}

// findSharedResourceDetails finds the shared resource for the provided premises
func findSharedResourceDetails(items []sharedResourceDetails, p PremisesType) (sharedResourceDetails, bool) {
	for _, it := range items {
		if it.IamID == p.SharedResourceDetails.OwnerIamID &&
			it.PremisesID == p.ID {
			return it, true
		}
	}
	return sharedResourceDetails{}, false
}

