func TestBPDetailsMiddleware(t *testing.T) {
	testCases := []struct {
		given  bool
		expLen int
	}{
		{given: true, expLen: 0},
		{given: false, expLen: 1},
	}
	for _, tc := range testCases {
		t.Run(fmt.Sprintf("from cache: %v", tc.given), func(t *testing.T) {
			// Given:
			w := httptest.NewRecorder()
			r := httptest.NewRequest(http.MethodPost, "/some/path", nil)
			ctx := r.Context()

			testWriter := testKafkaWriter{}

			oldPostal := postalCodeWriter
			postalCodeWriter = &testWriter
			defer func() { postalCodeWriter = oldPostal }()

			jwt := authc.JWTClaims{
				Sub:          "auth0|1234567890",
				Email:        "test@test.com",
				MobileNumber: "9000000",
			}
			ctx = authc.ProvidesJWT(ctx, jwt)

			bpDetails := bp.Details{
				FromCache: tc.given,
				JWT:       authc.JWTClaims{Sub: "IAM_ID"},
				Premises: []bp.PremisesType{
					{
						ID:     "PREMISEID",
						Type:   "PRIVATE",
						Active: true,
						ContestableDetails: bp.ContestableDetailsType{
							ContestableType: frcpo.ContestableTypeSP,
							AccountNumber:   "MSSLACC1",
							SignedUp:        true,
						},
						Accounts: []bp.AccountsType{
							{
								AccountNumber: "EBSACC1",
								AccountStatus: frcpo.AccountStatusActive,
								System:        frcpo.SystemEBS,
								Utilities:     []string{utilities.TypeGas, utilities.TypeWater},
							},
							{
