								AccountStatus: frcpo.AccountStatusActive,
								System:        frcpo.SystemMSSL,
								Utilities:     []string{utilities.TypeElectric},
							},
						},
						SharedResourceDetails: bp.SharedResourceDetailsType{
							Owner:      true,
							OwnerIamID: "IAM_ID",
						},
						AddressDetails: bp.AddressDetailsType{
							Postal: "108982",
						},
					},
				},
			}
			ctx = bp.ProvidesDetailsToContext(bpDetails, ctx)
			g := &errgroup.Group{}
			ctx = setErrgroupContext(ctx, g)

			// Mocks
			ctx = setupMocks(ctx)
			r = r.WithContext(ctx)
			var called bool
			h := web.Handler{H: func(w http.ResponseWriter, r *http.Request) error {
				called = true
				// Then:
				bpDetails := bp.DetailsFromRequest(r)
				require.NotNil(t, bpDetails)
				return nil
			}}

			// When:
			handler := middleware.Adapt(h, BPDetailsMiddleware())
			handler.ServeHTTP(w, r)

			// Then:
			require.True(t, called)
			require.NoError(t, g.Wait())
			require.Len(t, testWriter.Messages, tc.expLen)
		})
	}
}

var (
	_ kafkago.Writer = (*testKafkaWriter)(nil)
)

type testKafkaWriter struct {
